    if ".." in normalized_path.split(os.sep):
        pytest.fail("Path traversal detected in candidates file path")

    # Resolve the absolute path and ensure it is within the allowed directory
    real_path = os.path.abspath(normalized_path)
    if not real_path.startswith(_ALLOWED_CANDIDATES_DIR + os.sep):
        pytest.fail("Candidates file must reside within the allowed directory")

    # Verify the file exists
