        pytest.fail("Candidates file not found")

    # Enforce size limits (1â¯byte to 10â¯KB)
    try:
        file_size = os.path.getsize(real_path)
        if file_size == 0 or file_size > 10 * 1024:
            pytest.fail("Invalid candidates file size")
    except OSError as ose:
        pytest.fail(f"Unable to access candidates file: {ose}")

    # Safely deserialize using JSON (textâbased, no code execution)
    try:
        with open(real_path, "r", encoding="utf-8") as f:
