import sys
import os
import re
import logging
import zmq

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stderr)],
)


def _read_task_count() -> int:
    """Read a nonânegative integer from the user within a safe range (0â1000)."""
    while True:
        try:
            user_input = input("Enter number of tasks to dispatch (0â1000): ").strip()
            if not user_input:
                return 0
            count = int(user_input)
            if 0 <= count <= 1000:
                return count
            logging.warning("Please enter a value between 0 and 1000.")
        except (ValueError, TypeError):
            logging.warning("Invalid input. Please enter a numeric value.")


def _dispatch_tasks(sock: zmq.Socket, count: int) -> None:
    """Send ``count`` tasks safely over the given ZeroMQ socket."""
    for i in range(count):
        payload = str(i).encode("utf-8")
        try:
            sock.send(payload, zmq.NOBLOCK)
        except zmq.Again:
            continue
        except zmq.ZMQError:
            logging.exception("ZMQError occurred while sending a task.")
            continue


def _cleanup(sock: zmq.Socket | None, ctx: zmq.Context | None) -> None:
    """Close socket and terminate context while logging any errors."""
    if sock is not None:
        try:
            sock.close(linger=0)
        except zmq.ZMQError:
            logging.exception("Error closing ZeroMQ socket.")
    if ctx is not None:
        try:
            ctx.term()
        except Exception:
            logging.exception("Error terminating ZeroMQ context.")


def _validate_endpoint(endpoint: str) -> str:
    """Validate that the endpoint is a TCP address and optionally restrict the host."""
    pattern = re.compile(r"^tcp://(\d{1,3}\.){3}\d{1,3}:\d+$")
    if not pattern.match(endpoint):
        raise ValueError(f"Invalid ZMQ endpoint format: {endpoint}")

    host = endpoint.split("://")[1].split(":")[0]
    if host != "127.0.0.1":
        raise ValueError(f"Endpoint host {host} is not allowed.")
    return endpoint


def _load_curve_keys() -> dict | None:
    """Load CURVE keys from environment variables; return None if incomplete."""
    client_secret = os.getenv("ZMQ_CLIENT_SECRET_KEY")
    client_public = os.getenv("ZMQ_CLIENT_PUBLIC_KEY")
    server_key = os.getenv("ZMQ_SERVER_PUBLIC_KEY")
    if not all([client_secret, client_public, server_key]):
        logging.warning("CURVE keys not fully set; proceeding without encryption.")
        return None
    return {
        "client_secret": client_secret.encode(),
        "client_public": client_public.encode(),
        "server_key": server_key.encode(),
    }


def main() -> None:
    ctx: zmq.Context | None = None
    sink: zmq.Socket | None = None
    try:
        endpoint = os.getenv("ZMQ_ENDPOINT", "tcp://127.0.0.1:5555")
        endpoint = _validate_endpoint(endpoint)

        ctx = zmq.Context()
        sink = ctx.socket(zmq.PUSH)

        keys = _load_curve_keys()
        if keys:
            sink.curve_secretkey = keys["client_secret"]
            sink.curve_publickey = keys["client_public"]
            sink.curve_serverkey = keys["server_key"]

        sink.connect(endpoint)

        task_count = _read_task_count()
        _dispatch_tasks(sink, task_count)
        logging.info(f"Dispatched {task_count} task(s).")
    except KeyboardInterrupt:
        logging.error("Operation cancelled by user.")
    except Exception:
        logging.exception("An unexpected error occurred while dispatching tasks.")
    finally:
        _cleanup(sink, ctx)


if __name__ == "__main__":
    main()

