import os
import re
import sys
import subprocess
import logging
import argparse
from pathlib import Path

logging.basicConfig(level=logging.INFO, format='%(asctime)s %(levelname)s %(message)s')

BASE_DIR = Path.cwd().resolve()
ALLOWED_BUILD_CMDS = {"make", "ninja", "bazel"}

def is_safe_path(p):
    """Return True if the given path (str or Path) is under BASE_DIR and contains no NUL bytes."""
    if isinstance(p, str):
        if '�' in p:
            return False
        p = Path(p)
    try:
        resolved = p.resolve(strict=False)
    except Exception:
        return False
    try:
        return resolved.is_relative_to(BASE_DIR)
    except AttributeError:  # Python < 3.9
        return BASE_DIR == resolved or BASE_DIR in resolved.parents

def is_safe_rev(r: str) -> bool:
    return bool(re.fullmatch(r'[A-Fa-f0-9]{7,64}', r))

def _whitelisted_env() -> dict:
    path = os.getenv("WHITELISTED_PATH", "/usr/bin:/bin")
    return {
        "PATH": path,
        "LANG": "C",
        "LC_ALL": "C",
    }

def safe_run(
    cmd: list,
    *,
    cwd: Path | str | None = None,
    env: dict | None = None,
    timeout: int = 300,
) -> None:
    if env is None:
        env = _whitelisted_env()
    try:
        result = subprocess.run(
            cmd,
            cwd=cwd,
            env=env,
            check=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=timeout,
            close_fds=True,
        )
        logging.info("Command succeeded: %s", " ".join(map(str, cmd)))
    except subprocess.TimeoutExpired:
        logging.error("Command timed out: %s", " ".join(map(str, cmd)))
        sys.exit(1)
    except subprocess.CalledProcessError as e:
        logging.error("Command failed (exit %s): %s", e.returncode, e.stderr.strip())
        sys.exit(1)

def validate_symlinks(src: Path) -> bool:
    for root, dirs, files in os.walk(src, followlinks=False):
        for name in dirs + files:
            path = Path(root) / name
            if path.is_symlink():
                try:
                    target = path.resolve(strict=False)
                except Exception:
                    return False
                try:
                    if not target.is_relative_to(BASE_DIR):
                        return False
                except AttributeError:
                    if not (BASE_DIR == target or BASE_DIR in target.parents):
                        return False
    return True

def safe_copy(src: Path, dst: Path) -> None:
    if not validate_symlinks(src):
        logging.error("Unsafe symlink detected in source directory")
        sys.exit(1)
    safe_run(["cp", "-a", "-L", str(src), str(dst)])

def validate_build_cmd(cmd: str) -> bool:
    if cmd in ALLOWED_BUILD_CMDS:
        return True
    path = Path(cmd)
    if not path.is_absolute():
        return False
    if not is_safe_path(path):
        return False
    if not path.is_file():
        return False
    if not os.access(str(path), os.X_OK):
        return False
    try:
        stat = path.stat()
        if stat.st_uid != os.getuid():
            return False
    except Exception:
        return False
    return True

def is_valid_git_commit(rev: str, cwd: Path) -> bool:
    try:
        subprocess.run(
            ["git", "cat-file", "-e", f"{rev}^{{commit}}"],
            cwd=str(cwd),
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL,
            check=True,
        )
        return True
    except subprocess.CalledProcessError:
        return False

def main() -> None:
    parser = argparse.ArgumentParser(description="Secure build wrapper")
    parser.add_argument("--src-dir", required=True, help="Source directory")
    parser.add_argument("--dep-dir", required=True, help="Dependency directory")
    parser.add_argument("--rev", required=True, help="Git revision")
    parser.add_argument("--work-dir", required=True, help="Working directory")
    parser.add_argument("--ori-dir", required=True, help="Original directory")
    parser.add_argument("--build-cmd", required=True, help="Build command to execute")
    args = parser.parse_args()

    src_dir = Path(args.src_dir)
    dep_dir = Path(args.dep_dir)
    work_dir = Path(args.work_dir)
    ori_dir = Path(args.ori_dir)
    rev = args.rev
    build_cmd = args.build_cmd

    if not is_safe_path(src_dir):
        logging.error("Invalid source directory")
        sys.exit(1)
    if not is_safe_path(dep_dir):
        logging.error("Invalid dependency directory")
        sys.exit(1)
    if not is_safe_path(work_dir):
        logging.error("Invalid work directory")
        sys.exit(1)
    if not is_safe_path(ori_dir):
        logging.error("Invalid original directory")
        sys.exit(1)
    if not is_safe_rev(rev):
        logging.error("Invalid revision identifier")
        sys.exit(1)
    if not validate_build_cmd(build_cmd):
        logging.error("Build command not allowed")
        sys.exit(1)

    safe_copy(src_dir, work_dir)

    if not work_dir.is_dir():
        logging.error("Work directory does not exist after copy")
        sys.exit(1)

    if not is_valid_git_commit(rev, work_dir):
        logging.error("Revision does not refer to a valid commit")
        sys.exit(1)

    safe_run(["git", "checkout", "-f", rev], cwd=str(work_dir))
    safe_run(["git", "clean", "-fdx"], cwd=str(work_dir))

    build_env = _whitelisted_env()
    build_cmd_list = [build_cmd, "-p", str(dep_dir), str(work_dir)]
    safe_run(build_cmd_list, cwd=str(ori_dir), env=build_env)

if __name__ == "__main__":
    main()

