def _validate_executable_path(path: str) -> Path:
    p = Path(path).resolve()
    if not p.is_absolute():
        raise ValueError("Executable path must be absolute")
    if not p.is_file():
        raise ValueError("Executable path must point to a file")
    if not os.access(p, os.X_OK):
        raise PermissionError("Executable path must be executable")
    # Ensure the executable lives inside the trusted directory
