    # Preserve a minimal set of safe variables if they exist
    for var in ("HOME", "USER", "LOGNAME", "LANG", "LC_ALL"):
        if var in os.environ:
            env[var] = os.environ[var]
    return env


class TurqTestInstance:
    """Manages a Turq process for testing."""

    def __init__(self, turq_executable: str):
        if not isinstance(turq_executable, str):
            raise TypeError("Executable path must be a string")
        self.turq_path = _validate_executable_path(turq_executable)
        self.host = "127.0.0.1"
        self.mock_port = _validate_port(13095)
        self.editor_port = _validate_port(13096)
        self._process: subprocess.Popen | None = None
        self._lock = threading.Lock()
        self._shutdown_requested = threading.Event()
        self._env = _sanitized_env()

    def _build_cmd(self) -> list[str]:
        return [
            str(self.turq_path),
            "--host",
            self.host,
            "--port",
            str(self.mock_port),
            "--editor-port",
            str(self.editor_port),
        ]

    @staticmethod
    def _preexec_fn(executable_path: Path):
        # Reâvalidate in the child just before exec to mitigate TOCTOU
        if not executable_path.is_file() or not os.access(executable_path, os.X_OK):
            os._exit(1)

    def start(self, timeout: float = 5.0) -> None:
        with self._lock:
            if self._process is not None:
                raise RuntimeError("Turq instance already started")

            try:
                self._process = subprocess.Popen(
                    self._build_cmd(),
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE,
                    start_new_session=True,
                    close_fds=True,
                    env=self._env,
                    preexec_fn=lambda: self._preexec_fn(self.turq_path),
                )
            except Exception as exc:
                raise RuntimeError("Failed to launch Turq") from exc

            start_time = time.time()
            while time.time() - start_time < timeout:
                if self._shutdown_requested.is_set():
                    break
                if _is_port_open(self.host, self.mock_port):
                    # Verify the process is still alive
                    if self._process.poll() is None:
                        return
                time.sleep(0.1)

            # Failed to start within timeout â capture possible error output
            if self._process:
                stdout, stderr = self._process.communicate(timeout=0)
                if stdout:
                    logging.error("Turq stdout: %s", stdout.decode(errors='ignore').strip())
                if stderr:
                    logging.error("Turq stderr: %s", stderr.decode(errors='ignore').strip())
            self.stop()
            raise TimeoutError("Turq failed to start within the allotted time")

    def stop(self, timeout: float = 5.0) -> None:
        with self._lock:
            if self._process is None:
                return

            self._shutdown_requested.set()
            try:
                os.killpg(os.getpgid(self._process.pid), signal.SIGTERM)
            except Exception as exc:
                logging.warning("Failed to send SIGTERM to Turq process: %s", exc)

            try:
                self._process.wait(timeout=timeout)
            except subprocess.TimeoutExpired:
                try:
                    os.killpg(os.getpgid(self._process.pid), signal.SIGKILL)
                except Exception as exc:
                    logging.error("Failed to send SIGKILL to Turq process: %s", exc)
                self._process.wait()
            finally:
                self._process = None

    def __enter__(self):
        self.start()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.stop()
        return False

    def __del__(self):
        try:
            self.stop()
        except Exception as exc:
            logging.debug("Exception during TurqTestInstance cleanup: %s", exc)

