import logging
import numpy as np
from scipy import stats, optimize as opt

_logger = logging.getLogger(__name__)

def _is_finite_number(val):
    """Return True if val is a real finite number."""
    try:
        return np.isfinite(float(val))
    except Exception:
        return False

def ppcc_max(x, brack=(0.0, 1.0), dist='tukeylambda'):
    """Return the shape parameter that maximizes the probabilityâplot correlation
    coefficient for the given data to a oneâparameter family of distributions.

    Parameters
    ----------
    x : arrayâlike of shape (n,)
        Input data.
    brack : tuple or list of two floats, optional
        Lower and upper bounds for the shape parameter search.
    dist : str, optional
        Name of the distribution. Currently only ``'tukeylambda'`` is supported.

    Returns
    -------
    float
        Optimal shape parameter within the provided bounds.
    """
    # Validate input data
    arr = np.asarray(x, dtype=np.float64)
    if arr.ndim != 1:
        raise ValueError("Input data must be oneâdimensional")
    if arr.size < 2:
        raise ValueError("Input data must contain at least two elements")
    if not np.isfinite(arr).all():
        raise ValueError("Input data must contain only finite numbers")

    # Validate brack
    if not isinstance(brack, (list, tuple)) or len(brack) != 2:
        raise ValueError("brack must be a list or tuple of two numbers")
    low, high = brack[0], brack[1]
    if not (_is_finite_number(low) and _is_finite_number(high)):
        raise ValueError("Bracket bounds must be finite numbers")
    low, high = float(low), float(high)
    if low >= high:
        raise ValueError("Bracket lower bound must be less than upper bound")

    # Validate distribution name
    allowed_dists = {'tukeylambda'}
    if dist not in allowed_dists:
        raise ValueError(f"Unsupported distribution: {dist}")

    # Objective: negative PPCC (to maximize correlation)
    def _neg_ppcc(shape_param):
        if not _is_finite_number(shape_param):
            return np.inf
        try:
            osm, osr = stats.probplot(arr, dist=dist, sparams=(float(shape_param),))
            corr_matrix = np.corrcoef(osm, osr)
            # In rare numerical cases corrcoef can contain NaN
            if np.isnan(corr_matrix).any():
                return np.inf
            corr = corr_matrix[0, 1]
            if not np.isfinite(corr):
                return np.inf
            return -corr
        except Exception as e:
            _logger.debug("PPCC evaluation failed for shape=%s: %s", shape_param, e, exc_info=True)
            return np.inf

    try:
        result = opt.minimize_scalar(
            _neg_ppcc,
            bounds=(low, high),
            method='bounded',
            options={'xatol': 1e-6}
        )
    except Exception as e:
        _logger.exception("Optimization raised an unexpected exception")
        raise RuntimeError("Optimization failed") from e

    if not result.success:
        _logger.error("Optimization did not converge: %s", result.message)
        raise RuntimeError("Optimization did not converge")

    optimal_shape = float(result.x)
    if not _is_finite_number(optimal_shape):
        raise RuntimeError("Optimization produced a nonâfinite result")

    return optimal_shape

