MAX_MODEL_FILE_SIZE = 2 * 1024 * 1024  # 2 MB
MAX_JSON_DEPTH = 10
MAX_JSON_ITEMS = 5000
MAX_STRING_LENGTH = 1 * 1024 * 1024  # 1 MB

CONFIG_ATTR_WHITELIST = {
    "learning_rate": (float,),
    "batch_size": (int,),
    "mode": (str,),
    "max_iterations": (int,),
    "threshold": (float,),
