def _check_json_limits(obj, depth=0):
    if depth > MAX_JSON_DEPTH:
        raise ValueError("JSON exceeds maximum allowed depth")
    if isinstance(obj, dict):
        if len(obj) > MAX_JSON_ITEMS:
            raise ValueError("JSON contains too many items")
        for v in obj.values():
            _check_json_limits(v, depth + 1)
    elif isinstance(obj, list):
        if len(obj) > MAX_JSON_ITEMS:
            raise ValueError("JSON contains too many items")
        for item in obj:
            _check_json_limits(item, depth + 1)
    elif isinstance(obj, str):
        if len(obj) > MAX_STRING_LENGTH:
            raise ValueError("JSON string value exceeds maximum allowed length")


def load_model(self, filename: str):
    if not isinstance(filename, str):
        raise TypeError("filename must be a string")
    if len(filename) > 255:
        raise ValueError("filename is too long; maximum length is 255 characters")
    if not re.fullmatch(r'[A-Za-z0-9_\-]+', filename):
        raise ValueError("Invalid filename: only ASCII alphanumeric, hyphen and underscore are allowed")

    base_dir = getattr(self, "model_dir", ".")
    base_dir_abs = os.path.abspath(base_dir)
    model_path = os.path.abspath(os.path.join(base_dir_abs, f"{filename}.model"))
    if not model_path.startswith(base_dir_abs + os.sep):
        raise ValueError("Resolved path is outside the allowed model directory")

    if platform.system() != "Linux":
        raise NotImplementedError("load_model is implemented for Linux platforms only")

    fd = None
    try:
        fd = os.open(model_path, os.O_RDONLY | os.O_NOFOLLOW)

        try:
            real_path = os.readlink(f"/proc/self/fd/{fd}")
        except OSError:
            real_path = os.path.realpath(model_path)

        if not real_path.startswith(base_dir_abs + os.sep):
            raise ValueError("Resolved path after opening is outside the allowed model directory")

        stat_info = os.fstat(fd)
        if stat_info.st_size > MAX_MODEL_FILE_SIZE:
            raise ValueError("Model file exceeds maximum allowed size")

        with os.fdopen(fd, "rb") as f:
            fd = None  # fd will be closed by the context manager
            try:
                loaded = json.load(f)
            except json.JSONDecodeError as e:
                logging.error("Failed to decode JSON model '%s': %s", filename, e)
                raise

        _check_json_limits(loaded)

        if not isinstance(loaded, dict):
            raise TypeError("Loaded model data is not a dictionary")

        for attr, value in loaded.items():
            allowed_types = CONFIG_ATTR_WHITELIST.get(attr)
            if allowed_types is None:
                logging.warning(
                    "Ignored unauthorized attribute '%s' while loading model '%s'",
                    attr,
                    filename,
                )
                continue
            if not isinstance(value, allowed_types):
                logging.warning(
                    "Ignored attribute '%s' with invalid type %s while loading model '%s'",
                    attr,
                    type(value).__name__,
                    filename,
                )
                continue
            setattr(self, attr, value)

    finally:
        if fd is not None:
            try:
                os.close(fd)
            except OSError:
                pass

import re
