import logging
import sys
from typing import List, Sequence

import config

# Configure logger with a conservative default level.
logger = logging.getLogger(__name__)
logging.basicConfig(
    level=logging.WARNING,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stdout)],
)

_PROJECT_REGEX = re.compile(r"^[a-z][a-z0-9-]{4,28}[a-z0-9]$")
_BUCKET_REGEX = re.compile(r"^[a-z0-9][a-z0-9._-]{1,61}[a-z0-9]$")
_ALLOWED_REGIONS = {
    "us-central1",
    "us-east1",
    "us-west1",
    "europe-west1",
    "asia-east1",
}
_ALLOWED_RUNTIMES = {"nodejs18", "nodejs20"}

def _redact_name(name: str) -> str:
    if len(name) <= 2:
        return name
    return f"{name[0]}{'*' * (len(name) - 2)}{name[-1]}"

def _is_valid_cloud_function(name: str) -> bool:
    """Validate Cloud Function name per GCP rules."""
    return re.fullmatch(r"[A-Za-z][A-Za-z0-9_-]{0,62}", name) is not None

def _is_valid_gcp_project(project: str) -> bool:
    return isinstance(project, str) and bool(_PROJECT_REGEX.fullmatch(project))

def _is_valid_bucket_name(bucket: str) -> bool:
    return isinstance(bucket, str) and bool(_BUCKET_REGEX.fullmatch(bucket))

def _is_valid_region(region: str) -> bool:
    return isinstance(region, str) and region in _ALLOWED_REGIONS

def _is_valid_runtime(runtime: str) -> bool:
    return isinstance(runtime, str) and runtime in _ALLOWED_RUNTIMES

def _validate_config() -> None:
    if not _is_valid_gcp_project(config.TURBINIA_PROJECT):
        raise ValueError(f"Invalid GCP project ID: {config.TURBINIA_PROJECT}")
    if not _is_valid_bucket_name(config.BUCKET_NAME):
        raise ValueError(f"Invalid bucket name: {config.BUCKET_NAME}")
    if not _is_valid_region(config.TURBINIA_REGION):
        raise ValueError(f"Invalid region: {config.TURBINIA_REGION}")

def _sanitized_error(stderr: str) -> str:
    first_line = stderr.strip().splitlines()[0] if stderr else "No error output"
    return first_line[:200]

def _load_function_names() -> List[str]:
    """Retrieve and validate the list of functions to deploy from the config module."""
    if not hasattr(config, "FUNCTION_NAMES"):
        raise AttributeError("config module must define FUNCTION_NAMES")
    raw_names = getattr(config, "FUNCTION_NAMES")
    if not isinstance(raw_names, Sequence):
        raise TypeError("FUNCTION_NAMES must be a sequence")
    names: List[str] = []
    for item in raw_names:
        if not isinstance(item, str):
            raise TypeError("Each function name must be a string")
        stripped = item.strip()
        if not stripped:
            raise ValueError("Function name cannot be empty or whitespace only")
        names.append(stripped)
    return names

def main() -> None:
    # Load external configuration safely.
    try:
        config.LoadConfig()
    except Exception as e:
        logger.exception("Failed to load configuration: %s", str(e))
        sys.exit(1)

    try:
        _validate_config()
    except Exception as e:
        logger.exception("Configuration validation error: %s", str(e))
        sys.exit(1)

    runtime = "nodejs18"
    if not _is_valid_runtime(runtime):
        logger.error("Unsupported runtime selected: %s", runtime)
        sys.exit(1)

    try:
        function_names = _load_function_names()
    except Exception as e:
        logger.exception("Error loading function names: %s", str(e))
        sys.exit(1)

    for cloud_function in function_names:
        if not _is_valid_cloud_function(cloud_function):
            logger.warning("Skipped invalid function name: %s", _redact_name(cloud_function))
            continue

        logger.info("Deploying a Cloud Function")
        cmd_args: List[str] = [
            "gcloud",
            "--project",
            config.TURBINIA_PROJECT,
            "functions",
            "deploy",
            cloud_function,
            "--stage-bucket",
            config.BUCKET_NAME,
            "--region",
            config.TURBINIA_REGION,
            "--runtime",
            runtime,
            "--trigger-http",
            "--memory",
            "256MB",
            "--timeout",
            "60s",
        ]

        try:
            result = subprocess.run(
                cmd_args,
                capture_output=True,
                text=True,
                check=False,
                timeout=300,
                close_fds=True,
                env={},  # Run with a clean environment to avoid leaking secrets.
            )
            if result.returncode != 0:
                error_msg = _sanitized_error(result.stderr)
                logger.error(
                    "Deployment failed for %s: %s",
                    _redact_name(cloud_function),
                    error_msg,
                )
            else:
                logger.info(
                    "Deployment succeeded for %s",
                    _redact_name(cloud_function),
                )
        except subprocess.TimeoutExpired:
            logger.error(
                "Deployment timed out for %s",
                _redact_name(cloud_function),
            )
        except OSError as e:
            logger.error(
                "OS error during deployment of %s: %s",
                _redact_name(cloud_function),
                str(e),
            )
        except Exception:
            logger.exception(
                "Unexpected error during deployment of %s",
                _redact_name(cloud_function),
            )

if __name__ == "__main__":
    main()

