    """Return a set of all resolved IP addresses for the given hostname."""
    try:
        addr_info = socket.getaddrinfo(hostname, None)
    except socket.gaierror as e:
        raise ValueError(f'Unable to resolve hostname: {hostname}') from e
    ips = set()
    for _, _, _, _, sockaddr in addr_info:
        ip = sockaddr[0]
        ips.add(ip)
    return ips


def validate_dest_url(url: str) -> str:
    if not url:
        raise ValueError('Destination URL is required')
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme.lower() != 'https':
        raise ValueError('Only HTTPS scheme is allowed')
    if parsed.username or parsed.password:
        raise ValueError('URL must not contain credentials')
    if not parsed.netloc:
        raise ValueError('URL must contain a network location')
    hostname = parsed.hostname or ''
    if is_private_ip(hostname):
        raise ValueError('Destination host resolves to a private IP address')
    # Resolve and ensure none of the IPs are private
    resolved_ips = resolve_all(hostname)
    if not resolved_ips:
        raise ValueError('Hostname could not be resolved to any IP address')
    for ip in resolved_ips:
        if is_private_ip(ip):
            raise ValueError('Destination host resolves to a private IP address')
    # Return the normalized URL
    return urllib.parse.urlunparse(parsed)


def validate_auth_token(token: str) -> str:
    if not token:
        raise ValueError('Authorization token is required')
    if not TOKEN_REGEX.fullmatch(token):
        raise ValueError('Authorization token contains invalid characters')
    return token


class NoRedirectHandler(urllib.request.HTTPRedirectHandler):
    def redirect_request(self, req, fp, code, msg, hdrs, newurl):
        raise urllib.error.HTTPError(req.full_url, code, "Redirects are disabled", hdrs, fp)


class VerifiedHTTPSConnection(http.client.HTTPSConnection):
    def __init__(self, host, port=None, context=None, allowed_ips=None, **kwargs):
        super().__init__(host, port=port, context=context, **kwargs)
        self.allowed_ips = allowed_ips or set()

    def connect(self):
        super().connect()
        try:
            peer_ip = self.sock.getpeername()[0]
        except Exception as e:
            self.close()
            raise urllib.error.URLError('Failed to obtain peer IP address') from e
        if peer_ip not in self.allowed_ips:
            self.close()
            raise urllib.error.URLError('Peer IP address does not match resolved addresses')
        if is_private_ip(peer_ip):
            self.close()
            raise urllib.error.URLError('Peer IP address resolves to a private IP')


class VerifiedHTTPSHandler(urllib.request.HTTPSHandler):
    def __init__(self, context, allowed_ips):
        super().__init__(context=context)
        self.allowed_ips = allowed_ips

    def https_open(self, req):
        return self.do_open(
            lambda host, **kw: VerifiedHTTPSConnection(
                host,
                context=self._context,
                allowed_ips=self.allowed_ips,
                **kw
            ),
