def f(x: np.ndarray, blocksize: int) -> np.ndarray:
    b, c, h, w = x.shape
    tmp = np.reshape(x, (b, c, h // blocksize, blocksize, w // blocksize, blocksize))
    tmp = np.transpose(tmp, (0, 3, 5, 1, 2, 4))
    y = np.reshape(tmp, (b, c * (blocksize ** 2), h // blocksize, w // blocksize))
    return y


def safe_f(x: np.ndarray, blocksize: int) -> np.ndarray:
    if not isinstance(x, np.ndarray):
        raise TypeError("Input x must be a NumPy ndarray.")
    if not isinstance(blocksize, int):
        raise TypeError("Blocksize must be an integer.")
    if blocksize <= 0:
        raise ValueError("Blocksize must be a positive integer.")
    if blocksize > MAX_BLOCKSIZE:
        raise ValueError(f"Blocksize exceeds maximum allowed ({MAX_BLOCKSIZE}).")
    if x.ndim != 4:
        raise ValueError("Input array must be 4-dimensional.")
    b, c, h, w = x.shape
    if h % blocksize != 0 or w % blocksize != 0:
        raise ValueError("Blocksize must evenly divide height and width.")
    return f(x, blocksize)


def generate_random_tensor(batch: int, channels: int, height: int, width: int) -> np.ndarray:
    for name, value in (
        ("batch", batch),
        ("channels", channels),
        ("height", height),
        ("width", width),
    ):
        if not isinstance(value, int) or value <= 0:
            raise ValueError(f"{name} must be a positive integer.")
        if name == "batch" and value > MAX_BATCH:
            raise ValueError(f"{name} exceeds maximum allowed ({MAX_BATCH}).")
        if name == "channels" and value > MAX_CHANNELS:
            raise ValueError(f"{name} exceeds maximum allowed ({MAX_CHANNELS}).")
        if name == "height" and value > MAX_HEIGHT:
            raise ValueError(f"{name} exceeds maximum allowed ({MAX_HEIGHT}).")
        if name == "width" and value > MAX_WIDTH:
            raise ValueError(f"{name} exceeds maximum allowed ({MAX_WIDTH}).")

    total_elements = batch * channels * height * width
    if total_elements > MAX_TOTAL_ELEMENTS:
        raise ValueError(
            f"Requested tensor size ({total_elements} elements) exceeds allowed limit ({MAX_TOTAL_ELEMENTS})."
