class CategoryLoader:
    def __init__(self, base_path):
        # Resolve and store a trusted absolute base directory
        self.BASE_DIR = os.path.realpath(os.path.abspath(base_path))
        self.categories = {}
        self._load_categories()

    def _secure_open(self, path):
        """Open a file atomically without following symlinks and verify its location."""
        if not hasattr(os, "O_NOFOLLOW"):
            raise NotImplementedError("O_NOFOLLOW is not available on this platform")
        flags = os.O_RDONLY | os.O_NOFOLLOW
        if hasattr(os, "O_CLOEXEC"):
            flags |= os.O_CLOEXEC
        fd = os.open(path, flags)
        try:
            # Resolve the actual file path via /proc/self/fd (POSIX only)
            actual_path = os.path.realpath(os.readlink(f"/proc/self/fd/{fd}"))
            if os.path.commonpath([actual_path, self.BASE_DIR]) != self.BASE_DIR:
                raise ValueError("Path traversal detected after opening file")
            return os.fdopen(fd, "rb")
        except Exception:
            os.close(fd)
            raise

    def _validate_json_structure(self, data):
        """Ensure the loaded JSON conforms to expected minimal schema."""
        if not isinstance(data, dict):
            raise ValueError("Categories JSON must be an object")
        # Additional schema checks can be added here
        return data

    def _load_file(self, path):
        """Load and validate JSON from a securely opened file."""
        with self._secure_open(path) as cf:
            if os.fstat(cf.fileno()).st_size > MAX_JSON_SIZE:
                raise ValueError("Categories file exceeds maximum allowed size")
            raw_data = json.load(cf)
            return self._validate_json_structure(raw_data)

    def _load_categories(self):
        categories_path = os.path.realpath(os.path.join(self.BASE_DIR, "categories.json"))
        if os.path.commonpath([categories_path, self.BASE_DIR]) != self.BASE_DIR:
            raise ValueError("Path traversal attempt detected for categories file")
        try:
            self.categories = self._load_file(categories_path)
        except (json.JSONDecodeError, OSError, ValueError) as exc:
            logger.error("Failed to load categories: %s", exc)
            self.categories = {}
            # Recovery attempt
            try:
                scrape_wikipedia()  # Expected to write a fresh categories.json
                self.categories = self._load_file(categories_path)
            except (json.JSONDecodeError, OSError, ValueError) as rec_exc:
