import io
import hashlib
import inspect


_MAX_FILE_SIZE = 10 * 1024 * 1024  # 10â¯MiB default limit
_CHUNK_SIZE = 8192  # 8â¯KiB


def _is_builtin_method(method):
    """Return True only if the given callable is a builtâin (Câimplemented) method."""
    return inspect.isbuiltin(method)


def _validate_file_like(obj):
    """Validate that obj is a safe, builtâin fileâlike object."""
    allowed_types = (
        io.BytesIO,
        io.BufferedReader,
        io.BufferedIOBase,
        io.RawIOBase,
        io.TextIOWrapper,
        io.TextIOBase,
        io.FileIO,
    )
    if not isinstance(obj, allowed_types):
        raise TypeError("Unsupported file-like object type")

    if not (hasattr(obj, "read") and callable(obj.read) and _is_builtin_method(obj.read)):
        raise TypeError("File-like object must provide a builtâin read method")

    if hasattr(obj, "seek"):
        if not (callable(obj.seek) and _is_builtin_method(obj.seek)):
            raise TypeError("File-like object must provide a builtâin seek method")


def hash_file(file_like_object, max_bytes=_MAX_FILE_SIZE):
    """
    Generate a SHAâ256 hash for the contents of a validated fileâlike object.

    Args:
        file_like_object: A safe, builtâin fileâlike object supporting read (and optionally seek).
        max_bytes: Maximum number of bytes to process; defaults to 10â¯MiB.

    Returns:
        Hexadecimal SHAâ256 digest string.

    Raises:
        TypeError: If the input object is invalid.
        ValueError: If the file exceeds ``max_bytes``.
        OSError / IOError: Propagated I/O errors.
    """
    _validate_file_like(file_like_object)

    # Reset stream to start if seeking is supported
    if hasattr(file_like_object, "seek") and callable(file_like_object.seek):
        try:
            file_like_object.seek(0)
        except (OSError, IOError):
            # If we cannot seek, continue from the current position
            pass

    hasher = hashlib.sha256()
    total_read = 0

    while True:
        # Respect the maximum size limit
        remaining = max_bytes - total_read
        if remaining <= 0:
            raise ValueError("File size exceeds the allowed limit")
        to_read = min(_CHUNK_SIZE, remaining)

        try:
            chunk = file_like_object.read(to_read)
        except (OSError, IOError) as e:
            raise IOError("Failed to read from file-like object") from e

        if not chunk:
            break

        if isinstance(chunk, str):
            try:
                chunk = chunk.encode("utf-8")
            except UnicodeEncodeError as e:
                raise ValueError("Unable to encode file data to UTF-8") from e

        if not isinstance(chunk, (bytes, bytearray)):
            raise TypeError("File data must be bytes or str")

        hasher.update(chunk)
        total_read += len(chunk)

    return hasher.hexdigest()

import logging
import socket
from typing import Any, Dict, Iterable, Mapping, Sequence, Union

MAX_REPEATER_COUNT = 1000


def _decode_bytes(value: Union[bytes, str, None]) -> str:
    """Decode a bytes value to string safely, returning empty string on failure."""
    if isinstance(value, bytes):
        try:
            return value.decode(errors="replace")
        except Exception:
            return ""
    if isinstance(value, str):
        return value
    return ""


def _sanitize_for_logging(text: str) -> str:
    """Replace nonâprintable characters with a placeholder to avoid log injection."""
    return "".join(ch if ch.isprintable() else "?" for ch in text)


def _extract_status(loginres: Mapping[Any, Any]) -> str:
    """Get the status field from a login response dictionary."""
    raw_status = loginres.get(b"status", loginres.get("status"))
    return _decode_bytes(raw_status).strip()


def _extract_name(entry: Mapping[Any, Any]) -> str:
    """Retrieve and decode the name field from a repeater entry."""
    name_raw = entry.get(b"name", entry.get("name", b""))
    return _decode_bytes(name_raw)


def _extract_id(entry: Mapping[Any, Any]) -> Union[int, None]:
    """Retrieve and convert the id field from a repeater entry to an integer."""
    id_raw = entry.get(b"id", entry.get("id"))
    if id_raw is None:
        return None
    if isinstance(id_raw, int):
        return id_raw
    if isinstance(id_raw, (bytes, str)):
        try:
            return int(_decode_bytes(id_raw))
        except ValueError:
            return None
    return None


def process_response(
    s: socket.socket,
    loginres: Mapping[Any, Any],
    lst: Sequence[Mapping[Any, Any]],
) -> None:
    """
    Validate login response and process a list of repeater entries.
    All resources are cleaned up at the end of the call.
    """
    try:
        # ---- Validate login response ----
        if not isinstance(loginres, Mapping):
            logging.error("Login response is not a mapping")
            raise RuntimeError("Login failed")

        status_str = _extract_status(loginres)
        if status_str != "200":
            logging.warning("Login rejected, status: %s", status_str)
            raise RuntimeError("Login rejected")

        # ---- Validate repeater list ----
        if not isinstance(lst, (list, tuple)):
            logging.error("Repeater list is not a list or tuple")
            raise RuntimeError("Invalid repeater list")

        if len(lst) > MAX_REPEATER_COUNT:
            logging.error(
                "Repeater list too large: %d items (max %d)", len(lst), MAX_REPEATER_COUNT
            )
            raise RuntimeError("Repeater list exceeds allowed size")

        # ---- Process each repeater entry ----
        for entry in lst:
            if not isinstance(entry, Mapping):
                logging.debug("Skipping malformed repeater entry: %s", entry)
                continue

            name = _extract_name(entry)
            safe_name = _sanitize_for_logging(name)

            repeater_id = _extract_id(entry)
            if repeater_id is not None:
                logging.info("Available repeater: %s (ID %d)", safe_name, repeater_id)

    finally:
        # ---- Cleanup socket ----
        try:
            s.shutdown(socket.SHUT_RDWR)
        except OSError:
            pass
        finally:
            try:
                s.close()
            except Exception:
                logging.debug("Socket close raised an exception", exc_info=True)

