def _check_rate_limit(ip: str, limit: int = 5, period: int = 60) -> None:
    now = time.time()
    with _rate_limit_lock:
        timestamps = _rate_limit_data.get(ip, [])
        timestamps = [t for t in timestamps if now - t < period]
        if len(timestamps) >= limit:
            raise RuntimeError("Too many registration attempts, please try later")
        timestamps.append(now)
