MAX_JSON_BYTES = 1_048_576  # 1â¯MiB


def _redact_path(path: str) -> str:
    """Return a short, nondeterministic identifier for a path to avoid leaking sensitive information in logs."""
    return hashlib.sha256(path.encode("utf-8")).hexdigest()[:8]


def read_and_sanitize(msg_file_path: str):
    """Read a message file, validate its size, parse JSON if possible, and return a list of sanitized strings."""
    sanitized = []
    redacted_name = _redact_path(msg_file_path)

    try:
        # Enforce size limit before reading the whole file
        file_size = os.path.getsize(msg_file_path)
        if file_size == 0:
            logging.info("Message file %s is empty", redacted_name)
            return sanitized
        if file_size > MAX_JSON_BYTES:
            raise ValueError("Message file exceeds maximum allowed size")

        with open(msg_file_path, "r", encoding="utf-8") as f:
            raw_content = f.read()

        content = raw_content.strip()
        if not content:
            logging.info("Message file %s is empty after stripping whitespace", redacted_name)
            return sanitized

        # Attempt to treat the content as JSON
        try:
            payload = json.loads(content)
        except json.JSONDecodeError as e:
            logging.warning("JSON decode error in %s: %s", redacted_name, e)
            payload = None

        if isinstance(payload, list):
            allowed_types = (str, int, float, bool)
            for item in payload:
                if isinstance(item, allowed_types):
                    sanitized.append(str(item))
                else:
                    logging.warning(
                        "Unexpected item type %s in %s",
                        type(item).__name__,
                        redacted_name,
                    )
        else:
            # Plainâtext line; treat as a single entry
            sanitized.append(content)

    except (OSError, ValueError) as e:
        logging.error("Failed to process message file %s: %s", redacted_name, e)

    return sanitized

