        )

    try:
        with self._db.cursor() as cur:
            if isinstance(parameters, dict):
                cur.execute(query_template, parameters)
            else:
                cur.execute(query_template, tuple(parameters))

            if scope_normalized == "fetchone":
                result = cur.fetchone()
            else:  # fetchall
                result = cur.fetchall()
