def _open_no_follow(path: Path):
    """Open a file for reading without following symlinks."""
    fd = os.open(path, os.O_RDONLY | os.O_NOFOLLOW)
    return os.fdopen(fd, "rb")


def extract_if_gzipped(filename, *, overwrite: bool = False):
    """
    Decompress a .gz file safely.

    Args:
        filename (str or Path): Path to the input file.
        overwrite (bool): Allow overwriting an existing target file.

    Returns:
        Path: Path to the (possibly) decompressed file.

    Raises:
        ValueError: Invalid input or unsafe operation.
        RuntimeError: Decompression failures.
    """
    # Input validation
    if not isinstance(filename, (str, Path)):
        raise ValueError("filename must be a string or Path object")

    src_path = Path(filename)

    # Perform lstat to avoid following symlinks
    try:
        src_path.lstat()
    except FileNotFoundError as exc:
        raise ValueError(f"File does not exist: {src_path}") from exc

    # Reject symlink sources
    if src_path.is_symlink():
        raise ValueError("Source file must not be a symbolic link")

    if not src_path.is_file():
        raise ValueError(f"Path is not a regular file: {src_path}")

    # Only handle .gz files
    if src_path.suffix.lower() != ".gz":
        return src_path.resolve()

    target_path = src_path.with_suffix("")

    # Prevent arbitrary overwrite
    if target_path.exists():
        if not overwrite:
            raise ValueError(f"Target file already exists: {target_path}")
        if target_path.is_symlink():
            raise ValueError("Target path must not be a symbolic link")
        try:
            # Ensure we are removing a regular file, not following symlinks
            target_path.unlink()
        except OSError as exc:
            raise RuntimeError(f"Unable to remove existing target file: {target_path}") from exc

    # Decompress safely, writing directly to the final target using O_EXCL|O_NOFOLLOW
    try:
        with _open_no_follow(src_path) as comp_fp:
            with gzip.GzipFile(fileobj=comp_fp, mode="rb") as gz_fp:
                fd_target = os.open(
                    target_path,
                    os.O_WRONLY | os.O_CREAT | os.O_EXCL | os.O_NOFOLLOW,
                    0o644,
                )
                with os.fdopen(fd_target, "wb") as out_fp:
                    decompressed = 0
                    chunk_size = 64 * 1024
                    while True:
                        chunk = gz_fp.read(chunk_size)
                        if not chunk:
                            break
                        decompressed += len(chunk)
                        if decompressed > MAX_DECOMPRESSED_SIZE:
                            raise RuntimeError(
                                f"Decompressed size exceeds limit of {MAX_DECOMPRESSED_SIZE} bytes"
                            )
                        out_fp.write(chunk)

    except Exception as exc:
        # Cleanup partial target if it was created
        try:
            if target_path.exists():
                target_path.unlink()
        except OSError as cleanup_exc:
            log.debug(
                "Failed to cleanup partial target %s: %s", target_path, cleanup_exc
            )
        log.error("Failed to decompress %s: %s", src_path.name, exc)
        raise RuntimeError(f"Decompression failed for {src_path}") from exc

    return target_path.resolve()

