        caption = ann['caption']
        if not isinstance(caption, str):
            raise ValueError("Caption must be a string.")
        tokens = caption.lower().strip().split()
        if len(tokens) > MAX_TOKENS:
            raise ValueError(f"Caption exceeds maximum token limit of {MAX_TOKENS}.")
        caption_ids = [
