def read_settings(fn):
    """Read a simple key=value settings file into a dictionary.

    The function validates the filename, restricts it to a safe config
    directory, limits file size, sanitizes keys, and handles errors without
    leaking sensitive information.
    """
    # Validate input type
    if not isinstance(fn, str):
        raise TypeError("Filename must be a string")

    # Resolve to an absolute real path
    fn = os.path.realpath(fn)

    # Ensure the path resides within the allowed config directory
    if not fn.startswith(CONFIG_ROOT + os.sep):
        raise ValueError("Settings file must reside in the config directory")

    # Disallow symlinks to files outside the config directory
    if os.path.islink(fn):
        raise ValueError("Symlinks are not permitted for settings files")

    # Verify that the file exists and is a regular file
    if not os.path.isfile(fn):
        raise FileNotFoundError(f"Settings file not found: {fn}")

    # Protect against excessively large files (DoS mitigation)
    max_size = 1024 * 1024  # 1â¯MiB
    if os.path.getsize(fn) > max_size:
        raise ValueError("Settings file exceeds maximum allowed size")

    knh_data = {}

    try:
        with open(fn, "r", encoding="utf-8") as f:
            for line_no, raw_line in enumerate(f, start=1):
                line = raw_line.strip()

                # Skip empty lines and comments
                if not line or line.startswith("#"):
                    continue

                # Expect simple key=value format
                if "=" not in line:
                    continue  # malformed line; ignore silently

                key, value = line.split("=", 1)
                key = key.strip()
                value = value.strip()

                # Sanitize key: allow only alphanumeric characters and underscore,
                # must start with a letter or underscore, max length 64
                if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]{0,63}", key):
                    continue  # invalid key; ignore

                # Enforce a max length on the value to avoid abuse
                if len(value) > 4096:
                    continue  # value too long; ignore

                knh_data[key] = value

    except (OSError, IOError):
        # Raise a generic error without exposing internal details
        raise RuntimeError("Unable to read settings file") from None

    return knh_data

