import ctypes

def _is_admin() -> bool:
    if os.name != "nt":
        return os.getuid() == 0
    try:
        return ctypes.windll.shell32.IsUserAnAdmin() != 0
    except Exception:
        return False

def _get_taskkill_path() -> str:
    """Return the absolute path to taskkill.exe located in the real System32 directory."""
    GetSystemDirectoryW = ctypes.windll.kernel32.GetSystemDirectoryW
    buffer = ctypes.create_unicode_buffer(260)
    length = GetSystemDirectoryW(buffer, 260)
    if length == 0 or length > 260:
        raise OSError("Unable to retrieve System directory")
    system_dir = buffer.value
    candidate = os.path.join(system_dir, "taskkill.exe")
    if not os.path.isfile(candidate):
        raise FileNotFoundError("taskkill.exe not found in system directory")
    return candidate

def _kill_process_windows(pid: int) -> None:
    """Terminate a Windows process using native APIs, avoiding external executables."""
    PROCESS_TERMINATE = 0x0001
    kernel32 = ctypes.WinDLL("kernel32", use_last_error=True)

    handle = kernel32.OpenProcess(PROCESS_TERMINATE, False, pid)
    if not handle:
        err = ctypes.get_last_error()
        raise OSError(err, f"OpenProcess failed for PID {pid}")

    try:
        if not kernel32.TerminateProcess(handle, 0):
            err = ctypes.get_last_error()
            raise OSError(err, f"TerminateProcess failed for PID {pid}")
    finally:
        kernel32.CloseHandle(handle)

def KillProcessWithID(pid):
    """
    Terminate a process by its PID.
    Returns True on success, False on failure.
    """
    if not isinstance(pid, int):
        raise TypeError("pid must be an integer")
    if pid <= 0:
        raise ValueError("pid must be a positive integer")

    try:
        if platform.system().lower() == "windows":
            _kill_process_windows(pid)
        else:
            os.kill(pid, signal.SIGTERM)
        return True
    except ProcessLookupError:
        # Process does not exist â treat as already terminated
        return True
    except PermissionError:
        logging.error("Insufficient privileges to terminate process %d", pid)
        return False
    except OSError as e:
        logging.error("Failed to terminate process %d: %s", pid, e)
        return False
    except Exception:
        logging.exception("Unexpected error while terminating process %d", pid)
        return False

