        raise RuntimeError(f"Unable to read encryption key file: {path}") from exc


def _get_encryption_key() -> bytes:
    key_file = os.getenv("SECRET_ENC_KEY_FILE")
    if key_file:
        key = _load_key_from_file(key_file)
    else:
        key_b64 = os.getenv("SECRET_ENC_KEY")
        if not key_b64:
            raise RuntimeError(
                "Encryption key not set in SECRET_ENC_KEY or SECRET_ENC_KEY_FILE"
            )
        try:
            key = base64.b64decode(key_b64, validate=True)
        except Exception as exc:
            raise RuntimeError("Invalid encryption key format") from exc
    if len(key) != 32:
        raise RuntimeError("Encryption key must be 32 bytes for AES-256-GCM")
    return key


def _encrypt_secret_value(value: Any) -> str:
    raw = value if isinstance(value, bytes) else str(value).encode("utf-8")
    key = _get_encryption_key()
    aesgcm = AESGCM(key)
    nonce = os.urandom(12)
    ciphertext = aesgcm.encrypt(nonce, raw, None)
    encrypted_blob = nonce + ciphertext
    return base64.b64encode(encrypted_blob).decode("utf-8")


def _sanitize_secret_value(value: Any) -> str:
    return _encrypt_secret_value(value)


def _redact_secret_patterns(text: str) -> str:
    text = _BASE64_RE.sub("[REDACTED]", text)
    text = _SECRET_PATTERN_RE.sub(r"=[REDACTED]", text)
    return text


def _build_env() -> Dict[str, str]:
    """Construct a safe environment dict containing only whitelisted variables."""
    return {k: v for k, v in os.environ.items() if k in _ENV_WHITELIST}


def _hash_file(path: str) -> str:
    """Return SHA256 hash of a file's contents."""
    sha256 = hashlib.sha256()
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


