            raise RuntimeError("Failed to serialize secret to YAML") from exc

    def _run_oc(self, args: List[str], input_data: Optional[str] = None) -> subprocess.CompletedProcess:
        cmd = [self.oc_path] + args
        env = _build_env()
        try:
            result = subprocess.run(
                cmd,
                input=input_data,
                capture_output=True,
                text=True,
                env=env,
                timeout=_TIMEOUT_SECONDS,
                check=False,
