    @staticmethod
    def _configureSSHServer(vm, path) -> bool:
        """
        Regenerates SSH host keys inside the VM filesystem located at *path*.
        All operations are performed securely without invoking a shell.
        """
        base_path = pathlib.Path("/var/lib/ofelia/vms")
        vm_path = pathlib.Path(path)

        base_fd: Optional[int] = None
        vm_fd: Optional[int] = None
        ssh_dir_fd: Optional[int] = None

