        O_FLAGS = os.O_RDONLY | os.O_DIRECTORY | os.O_NOFOLLOW
        if hasattr(os, "O_PATH"):
            O_FLAGS |= os.O_PATH

        try:
            # Resolve and validate the provided path
            base_real = base_path.resolve()
            vm_real = vm_path.resolve()
            try:
                vm_real.relative_to(base_real)
            except ValueError:
                OfeliaDebianVMConfigurator.logger.error(
                    "Path validation failed: path outside allowed directory"
                )
                return False

            # Open base directory safely
            base_fd = os.open(str(base_real), O_FLAGS)

            # Open VM directory safely
            vm_fd = os.open(str(vm_real), O_FLAGS)

            # Open ssh directory inside the VM
            ssh_dir_path = vm_real / "etc" / "ssh"
            ssh_dir_fd = os.open(str(ssh_dir_path), O_FLAGS)

            # Verify ssh_dir is indeed a directory (defensive)
            if not stat.S_ISDIR(os.fstat(ssh_dir_fd).st_mode):
                OfeliaDebianVMConfigurator.logger.error(
                    "SSH directory is not a directory"
                )
                return False

            # Remove existing SSH host keys safely (skip symlinks)
            OfeliaDebianVMConfigurator.logger.debug("Removing existing SSH host keys...")
            with os.scandir(ssh_dir_fd) as it:
                for entry in it:
                    if not entry.name.startswith("ssh_host_"):
                        continue
                    try:
                        entry_stat = entry.stat(follow_symlinks=False)
                    except Exception as st_err:
                        OfeliaDebianVMConfigurator.logger.warning(
                            "Failed to stat %s: %s", entry.name, st_err
                        )
                        continue
                    if stat.S_ISREG(entry_stat.st_mode):
                        try:
                            os.unlink(entry.name, dir_fd=ssh_dir_fd)
                        except Exception as rm_err:
