                if key_bits:
                    cmd.extend(["-b", key_bits])

                OfeliaDebianVMConfigurator.logger.debug(
                    "Generating %s SSH host key", key_type
                )

                result = subprocess.run(
                    cmd,
                    capture_output=True,
                    text=True,
                    check=False,
                    env=safe_env,
