def _is_safe_primitive(val):
    return isinstance(val, (str, int, float, bool, type(None)))


def _validate_safe(value):
    """Recursively ensure that only immutable, serialisable primitives are stored."""
    if _is_safe_primitive(value):
        return True
    if isinstance(value, dict):
        for k, v in value.items():
            if not _is_safe_primitive(k):
                return False
            if not _validate_safe(v):
                return False
        return True
    if isinstance(value, (list, tuple, set)):
        for item in value:
            if not _validate_safe(item):
                return False
        return True
    return False


