def _is_within_base(path: Path) -> bool:
    """Return True if path is a descendant of BASE_DIR (or the base itself)."""
    try:
        path.relative_to(BASE_DIR)
        return True
    except ValueError:
        return False

def get_secure_path(user_path: str) -> Path:
    """Resolve user supplied path and ensure it stays within BASE_DIR."""
    p = Path(user_path).expanduser().resolve()
    if not _is_within_base(p):
        raise ValueError('File path is outside the permitted directory')
    return p

def open_secure_file(path: Path, encoding: str = 'utf-8'):
    """Open a file safely, performing all checks after the file descriptor is obtained."""
    flags = os.O_RDONLY | os.O_CLOEXEC
    if hasattr(os, 'O_NOFOLLOW'):
        flags |= os.O_NOFOLLOW

    fd = os.open(str(path), flags)
    try:
        st = os.fstat(fd)

        # Must be a regular file
        if not stat.S_ISREG(st.st_mode):
            raise OSError('Opened file is not a regular file')

        # Disallow hardâlinked files (link count > 1)
        if st.st_nlink != 1:
            raise OSError('File has multiple hard links (potential hardâlink attack)')

        # Enforce maximum size
        if st.st_size > MAX_FILE_SIZE:
            raise OSError('File exceeds maximum allowed size')

        # Validate extension (caseâinsensitive)
        if Path(path).suffix.lower() not in ALLOWED_EXTENSIONS:
            raise ValueError('File type is not allowed')

        # Ensure the opened file resides on the same filesystem as BASE_DIR
        if st.st_dev != base_stat.st_dev:
            raise OSError('File resides on a different filesystem than BASE_DIR')

        return os.fdopen(fd, 'r', encoding=encoding)
    except Exception:
        os.close(fd)
        raise

