class FormSubmissionError(AssertionError):
    """Raised when form submission fails without leaking internal details."""


def test_invalid_login(form: Any) -> None:
    """
    Verify that submitting an invalid password returns a generic authentication error
    and does not leak internal details.
    """
    # Verify that the object implements the expected interface
