        raise AssertionError("Response does not contain text content.")
    if "Invalid email or password" not in response.text:
        raise AssertionError("Expected generic auth error not found.")

    # Ensure no sensitive internal details are exposed
    for keyword in ("Traceback", "Exception"):
        if keyword in response.text:
            raise AssertionError(f"Sensitive information '{keyword}' exposed in response.")

