from django.conf import settings

_logger = logging.getLogger(__name__)

_ALLOWED_ALGORITHMS = {
    "sha256": hashlib.sha256,
    "sha384": hashlib.sha384,
    "sha512": hashlib.sha512,
}


def compute_file_hash(file_path, algorithm="sha256"):
    # Validate hashing algorithm
    if algorithm not in _ALLOWED_ALGORITHMS:
        raise ValueError(f"Unsupported hash algorithm: {algorithm}")
    hasher = _ALLOWED_ALGORITHMS[algorithm]()

    # Resolve and validate the file path
    try:
        base = Path(settings.STATIC_ROOT).resolve()
        target = Path(file_path).resolve()
        if not target.is_relative_to(base):
            raise ValueError("Path traversal detected")
    except Exception as exc:
        _logger.debug("Path validation error: %s", exc)
        return None

    # Open the file atomically and compute hash
    try:
        flags = os.O_RDONLY
        if hasattr(os, "O_NOFOLLOW"):
            flags |= os.O_NOFOLLOW
        fd = os.open(str(target), flags)
        with os.fdopen(fd, "rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                hasher.update(chunk)
    except (FileNotFoundError, PermissionError, OSError) as exc:
        _logger.debug("File read error: %s", exc)
        return None

    return hasher.hexdigest()

