import io

def process(self):
    bytes_written = 0
    try:
        src_path = pathlib.Path(self.path)

        # Disallow symlinks
        if src_path.is_symlink():
            raise RuntimeError("Symlink not allowed for source path")

        # Open source file securely, avoiding TOCTOU race conditions
        if hasattr(os, "O_NOFOLLOW"):
            flags = os.O_RDONLY | os.O_NOFOLLOW
        else:
            flags = os.O_RDONLY
        fd = os.open(str(src_path), flags)

        with io.TextIOWrapper(os.fdopen(fd, "rb"), encoding="utf-8", errors="replace") as src_file:
