MAX_COMMANDS = int(os.getenv("MAX_COMMANDS", "20"))
MAX_CMD_LENGTH = int(os.getenv("MAX_CMD_LENGTH", "200"))
MAX_ARGS = int(os.getenv("MAX_ARGS", "10"))
MAX_ARG_LENGTH = int(os.getenv("MAX_ARG_LENGTH", "100"))
MAX_OUTPUT_SIZE = int(os.getenv("MAX_OUTPUT_SIZE", "4096"))  # bytes
TIMEOUT = int(os.getenv("TIMEOUT", "5"))  # seconds
CPU_TIME_LIMIT = int(os.getenv("CPU_TIME_LIMIT", "2"))  # seconds
MEMORY_LIMIT = int(os.getenv("MEMORY_LIMIT", str(50 * 1024 * 1024)))  # 50 MB

ALLOWED_COMMANDS = {
    "ls": ["/bin/ls"],
    "cat": ["/bin/cat"],
    "echo": ["/bin/echo"],
}

# Whitelisted flags per command (exact strings)
ALLOWED_FLAGS = {
    "ls": {"-l", "-a", "-h", "--color=never"},
    "cat": set(),
    "echo": set(),
}


def _is_path_within_sandbox(path: str, sandbox_dir: str) -> bool:
    sandbox_real = os.path.realpath(sandbox_dir)
    try:
        target = os.path.realpath(path)
    except Exception:
        return False
    return target == sandbox_real or target.startswith(sandbox_real + os.sep)


def _validate_arguments(args, sandbox_dir):
    # args[0] is command name (already validated)
    if len(args) - 1 > MAX_ARGS:
        return False
    cmd_name = os.path.basename(args[0])
    allowed_flags = ALLOWED_FLAGS.get(cmd_name, set())
    for arg in args[1:]:
        if len(arg) > MAX_ARG_LENGTH:
            return False
        if arg.startswith("-"):
            # support combined short options like -la
            if arg in allowed_flags:
                continue
            if arg.startswith("--"):
                # long option not exactly whitelisted
                if arg not in allowed_flags:
                    return False
            else:
                # check each char after '-'
                for ch in arg[1:]:
                    if f"-{ch}" not in allowed_flags:
                        return False
                continue
        candidate = arg
        if not os.path.isabs(candidate):
            candidate = os.path.join(sandbox_dir, candidate)
        # reject any symlink to avoid TOCTOU path tricks
        try:
            if os.path.islink(candidate):
                return False
            st = os.stat(candidate)
            if not os.path.isfile(candidate):
                return False
        except Exception:
            return False
        if not _is_path_within_sandbox(candidate, sandbox_dir):
            return False
    return True


def _drop_privileges():
    pw = pwd.getpwnam("nobody")
    # ensure the process has the capability to drop privileges
    os.setgid(pw.pw_gid)
    os.setuid(pw.pw_uid)
    # Verify drop
    if os.geteuid() != pw.pw_uid or os.getegid() != pw.pw_gid:
        raise PermissionError("Failed to drop privileges to 'nobody'")


def _apply_resource_limits():
    resource.setrlimit(resource.RLIMIT_CPU, (CPU_TIME_LIMIT, CPU_TIME_LIMIT))
    resource.setrlimit(resource.RLIMIT_AS, (MEMORY_LIMIT, MEMORY_LIMIT))
    # Additional limits
    resource.setrlimit(resource.RLIMIT_DATA, (MEMORY_LIMIT, MEMORY_LIMIT))
    resource.setrlimit(resource.RLIMIT_RSS, (MEMORY_LIMIT, MEMORY_LIMIT))


def _preexec():
    _drop_privileges()
    _apply_resource_limits()


