        if not re.fullmatch(r"[A-Za-z0-9._-]+", name):
            raise ValueError("Filename contains invalid characters")
        # Reâconstruct a safe relative path using only the allowed name
        return str(pathlib.PurePath(name))

    def _compute_hmac(self, data: bytes) -> bytes:
        return hmac.new(self._HMAC_KEY, data, hashlib.sha256).hexdigest().encode("utf-8")

    def _encrypt(self, plaintext: bytes) -> bytes:
