import os
import re
import ipaddress
import subprocess
import shutil

BASE_DIR = "/opt/naviseccli"
ALLOWED_EXECUTABLES = {"naviseccli"}
# Define a safe environment whitelist (remove dangerous vars)
_DANGEROUS_ENV_VARS = {"LD_LIBRARY_PATH", "LD_PRELOAD", "PYTHONPATH", "PYTHONHOME"}


def _validate_ip(ip):
    try:
        ipaddress.ip_address(ip)
        return ip
    except ValueError as exc:
        raise ValueError("Invalid IP address") from exc


def _validate_path(path, base_dir=BASE_DIR):
    if not os.path.isabs(path):
        raise ValueError("Path must be absolute")
    real_path = os.path.realpath(path)
    base_real = os.path.realpath(base_dir)
    if not (real_path == base_real or real_path.startswith(base_real + os.sep)):
        raise ValueError("Path traversal detected")
    return real_path


def _resolve_executable(exe):
    # Ensure the executable name is allowed
    if os.path.basename(exe) not in ALLOWED_EXECUTABLES:
        raise ValueError(f"Executable '{os.path.basename(exe)}' is not allowed")
    # Resolve to an absolute path
    if not os.path.isabs(exe):
        resolved = shutil.which(exe)
        if resolved is None:
            raise ValueError(f"Executable '{exe}' not found in PATH")
        exe_path = resolved
    else:
        exe_path = exe
    exe_path = os.path.realpath(exe_path)
    base_dir_real = os.path.realpath(BASE_DIR)
    if not (exe_path == base_dir_real or exe_path.startswith(base_dir_real + os.sep)):
        raise ValueError("Executable resides outside allowed directory")
    return exe_path


def _validate_arguments(args):
    """
    Validate each argument passed to the allowed executable.
    Only alphanumeric characters, dash, underscore, dot, slash are permitted.
    """
    pattern = re.compile(r'^[\w\-\./]+$')
    for arg in args:
        if not isinstance(arg, str):
            raise TypeError("Command arguments must be strings")
        if len(arg) == 0:
            raise ValueError("Empty command argument is not allowed")
        if len(arg) > 255:
            raise ValueError("Command argument exceeds maximum length")
        if not pattern.match(arg):
            raise ValueError(f"Invalid characters in command argument: {arg}")


def _sanitize_environment():
    """
    Return a copy of the current environment with dangerous variables removed.
    """
    env = {k: v for k, v in os.environ.items() if k not in _DANGEROUS_ENV_VARS}
    # Ensure a minimal PATH is present
    if "PATH" not in env:
        env["PATH"] = "/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin"
    return env


def _run_command(cmd, check=False, timeout=None):
    if not isinstance(cmd, (list, tuple)):
        raise TypeError("Command must be a list or tuple")
    if not cmd:
        raise ValueError("Command cannot be empty")
    for part in cmd:
        if not isinstance(part, str):
            raise TypeError("Command parts must be strings")
    # Resolve and validate the executable
    exe_path = _resolve_executable(cmd[0])
    # Validate remaining arguments
    _validate_arguments(cmd[1:])
    full_cmd = [exe_path] + list(cmd[1:])
    return subprocess.run(
        full_cmd,
        check=check,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        timeout=timeout,
        shell=False,
        env=_sanitize_environment(),
    )


def _mock_run(cmd, check=False, stdout=subprocess.PIPE, stderr=subprocess.PIPE, timeout=None):
    """
    Mock version of _run_command that validates input without executing the command.
    """
    if not isinstance(cmd, (list, tuple)):
        raise TypeError("Command must be a list or tuple")
    if not cmd:
        raise ValueError("Command cannot be empty")
    for part in cmd:
        if not isinstance(part, str):
            raise TypeError("Command parts must be strings")
    # Perform the same validation steps as the real runner
    _resolve_executable(cmd[0])
    _validate_arguments(cmd[1:])
    # Return a fabricated CompletedProcess
    return subprocess.CompletedProcess(
        args=cmd,
        returncode=0,
        stdout=b'OK',
        stderr=b'',
    )

