import subprocess
import logging
import os
import stat
import shutil
from pathlib import Path

_logger = logging.getLogger(__name__)

_ALLOWED_PS_PATHS = (
    Path("/bin/ps"),
    Path("/usr/bin/ps"),
)


def _is_safe_executable(path: Path) -> bool:
    try:
        if not path.is_file():
            return False
        mode = path.stat().st_mode
        # Must be a regular file, owned by root, and not writable by group or others
        if (mode & stat.S_IWGRP) or (mode & stat.S_IWOTH):
            return False
        # Disallow setuid/setgid bits
        if (mode & stat.S_ISUID) or (mode & stat.S_ISGID):
            return False
        if path.stat().st_uid != 0:
            return False
        return True
    except OSError:
        return False


def _resolve_ps_path_atomically() -> str:
    """
    Resolve a safe path to the `ps` executable, performing checks atomically
    to avoid TOCTOU race conditions.
    """
    for candidate in _ALLOWED_PS_PATHS:
        try:
            fd = os.open(candidate, os.O_RDONLY | getattr(os, "O_NOFOLLOW", 0))
            try:
                st = os.fstat(fd)
                if not stat.S_ISREG(st.st_mode):
                    continue
                if st.st_uid != 0:
                    continue
                if (st.st_mode & (stat.S_IWGRP | stat.S_IWOTH | stat.S_ISUID | stat.S_ISGID)):
                    continue
                # Obtain the canonical path via /proc
                resolved = os.readlink(f"/proc/self/fd/{fd}")
                return resolved
            finally:
                os.close(fd)
        except OSError:
            continue

    # Fallback: search in trusted system directories only
    for directory in ("/bin", "/usr/bin"):
        ps_path = os.path.join(directory, "ps")
        try:
            fd = os.open(ps_path, os.O_RDONLY | getattr(os, "O_NOFOLLOW", 0))
            try:
                st = os.fstat(fd)
                if st.st_uid == 0 and not (st.st_mode & (stat.S_IWGRP | stat.S_IWOTH | stat.S_ISUID | stat.S_ISGID)):
                    resolved = os.readlink(f"/proc/self/fd/{fd}")
                    return resolved
            finally:
                os.close(fd)
        except OSError:
            continue

    raise EnvironmentError("Safe 'ps' executable not found")


def getpcmd(pid):
    """
    Returns the command line of a process.

    :param pid: Process ID (int or numeric string).
    :return: Command line string or None if unavailable.
    :raises ValueError: If ``pid`` is not a positive integer.
