        Execute a command securely with its working directory bound to an opened file descriptor.
        """
        try:
            subprocess.run(
                cmd_args,
                input=input_data,
                cwd=f"/proc/self/fd/{cwd_fd}",
                check=True,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                close_fds=True,
                text=False,
            )
        except subprocess.CalledProcessError as exc:
            OfeliaDebianVMConfigurator.logger.error(
