def _int_env(var_name: str, default: int) -> int:
    """Safely read integer environment variables with fallback."""
    value = os.getenv(var_name)
    if value is None:
        return default
    try:
        return int(value)
    except (ValueError, TypeError):
        logger.warning(
            "Invalid integer for %s: %s â using default %s",
            var_name,
