def fetch_union(streams, cursors):
    # Configuration â can be overridden via environment variables (validated)
    MAX_TABLE_NAME_LENGTH = _int_env("MAX_TABLE_NAME_LENGTH", 64)
    MAX_ROWS_PER_TABLE = _int_env("MAX_ROWS_PER_TABLE", 10_000)
    MAX_TOTAL_ROWS = _int_env("MAX_TOTAL_ROWS", 50_000)
    FETCH_BATCH_SIZE = _int_env("FETCH_BATCH_SIZE", 1_000)

    # Strict, immutable whitelist
    ALLOWED_TABLES = {"users", "orders", "products"}

    # ------------------------------------------------------------------
    # Input validation â strict whitelist and pattern check
    # ------------------------------------------------------------------
    validated_streams = []
    for stream in streams:
        name = stream.strip()
        if (
            len(name) > MAX_TABLE_NAME_LENGTH
            or not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", name)
        ):
            raise functions.OperatorError(
                __name__.rsplit(".")[-1],
                f"Invalid table name detected: '{name}'",
            )
        if name not in ALLOWED_TABLES:
            raise functions.OperatorError(
                __name__.rsplit(".")[-1],
                f"Table name not allowed: '{name}'",
            )
        validated_streams.append(name)

    if not validated_streams:
        return {"columns": [], "rows": []}

    # ------------------------------------------------------------------
    # Ensure psycopg2 is available â required for safe identifier quoting
    # ------------------------------------------------------------------
    try:
        from psycopg2 import sql, Error as PsycopgError  # type: ignore
        db_exceptions = (PsycopgError,)
    except ImportError as exc:
        logger.error("Required database driver psycopg2 is not available")
        raise functions.OperatorError(
            __name__.rsplit(".")[-1],
            "Database driver not available",
        ) from exc

    column_names = None
    union_rows = []

    for cursor, table_name in zip(cursors, validated_streams):
        try:
            # --------------------------------------------------------------
            # Build and execute a safe query using psycopg2.sql utilities
            # --------------------------------------------------------------
            if column_names is None:
                query = sql.SQL("SELECT * FROM {}").format(sql.Identifier(table_name))
            else:
                cols_sql = sql.SQL(", ").join(sql.Identifier(col) for col in column_names)
                query = sql.SQL("SELECT {} FROM {}").format(cols_sql, sql.Identifier(table_name))

            cursor.execute(query)
            try:
                logger.debug(
                    "Executed query for table %s: %s",
                    table_name,
                    query.as_string(cursor),
                )
            except Exception:
                logger.debug("Executed query for table %s (composed object)", table_name)

            # --------------------------------------------------------------
            # Capture column metadata and enforce consistency
            # --------------------------------------------------------------
            if column_names is None:
                column_names = [desc[0] for desc in cursor.description]
            else:
                current_cols = [desc[0] for desc in cursor.description]
                if current_cols != column_names:
                    raise functions.OperatorError(
                        __name__.rsplit(".")[-1],
                        "Column mismatch between union tables",
                    )

            # --------------------------------------------------------------
            # Retrieve rows in controlled batches respecting limits
            # --------------------------------------------------------------
            rows_fetched = 0
            while rows_fetched < MAX_ROWS_PER_TABLE:
                batch = cursor.fetchmany(FETCH_BATCH_SIZE)
                if not batch:
                    break

                # Enforce global total rows limit
                if len(union_rows) + len(batch) > MAX_TOTAL_ROWS:
                    excess = (len(union_rows) + len(batch)) - MAX_TOTAL_ROWS
                    batch = batch[: len(batch) - excess]
                    union_rows.extend(batch)
                    logger.warning(
                        "Global row limit of %d reached; truncating results",
                        MAX_TOTAL_ROWS,
                    )
                    break

                union_rows.extend(batch)
                rows_fetched += len(batch)

            if rows_fetched >= MAX_ROWS_PER_TABLE:
                logger.warning(
                    "Row limit reached for table '%s' (limit=%d)",
                    table_name,
                    MAX_ROWS_PER_TABLE,
                )

        except db_exceptions as db_exc:
            # Log generic error message; detailed traceback at DEBUG level
            logger.error("Database error while processing request")
            logger.debug("Database exception details:", exc_info=True)
            raise functions.OperatorError(
                __name__.rsplit(".")[-1],
                f"Error querying table '{table_name}'",
            ) from db_exc

        except Exception as exc:
            logger.error("Unexpected error while processing request")
            logger.debug("Unexpected exception details:", exc_info=True)
            raise

    return {"columns": column_names or [], "rows": union_rows}

