import os
import io
import time
import re
import logging

logger = logging.getLogger(__name__)

# Configuration
BASE_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), "stats"))
MAX_FILE_SIZE = 1 * 1024 * 1024  # 1â¯MiB


def _resolve_safe_path(path: str) -> str:
    """Resolve the absolute path and ensure it is inside BASE_DIR."""
    real_path = os.path.realpath(path)
    if os.path.commonpath([real_path, BASE_DIR]) != BASE_DIR:
        raise ValueError("Stat file path is outside the allowed directory.")
    return real_path


def _wait_and_open_file(path: str, timeout: int = 30) -> int:
    """
    Wait for a file to appear and open it atomically.
    Returns a file descriptor opened with O_RDONLY (and O_NOFOLLOW when supported).
    """
    waited = 0
    flags = os.O_RDONLY
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW

    while True:
        try:
            fd = os.open(path, flags)
            # If O_NOFOLLOW is not supported, explicitly reject symlinks.
            if not hasattr(os, "O_NOFOLLOW") and os.path.islink(path):
                os.close(fd)
                raise OSError("Symlink detected for stat file.")
            return fd
        except FileNotFoundError:
            if waited >= timeout:
                raise FileNotFoundError(f"Required file '{path}' not found within {timeout}s.")
            time.sleep(1)
            waited += 1
        except OSError:
            # Propagate other OS errors (e.g., permission denied, symlink loop)
            raise


def _parse_stat_lines(lines):
    """Parse lines of a stat file into a dict with strict validation."""
    stats = {}
    for lineno, raw in enumerate(lines, start=1):
        line = raw.strip()
        if not line or line.startswith('#'):
            continue

        if '=' not in line:
            raise ValueError(f"Invalid format in stat file at line {lineno}.")
        key, value = map(str.strip, line.split('=', 1))

        if not re.fullmatch(r'[A-Za-z_][A-Za-z0-9_]*', key):
            raise ValueError(f"Invalid key name in stat file at line {lineno}.")

        if re.fullmatch(r'-?\d+', value):
            parsed_value = int(value)
        elif re.fullmatch(r'-?\d+\.\d+', value):
            parsed_value = float(value)
        else:
            raise ValueError(f"Invalid value type in stat file at line {lineno}.")

        stats[key] = parsed_value
    return stats


def read_stat_file(stat_file):
    """Securely read and parse the dgen stat file."""
    try:
        safe_path = _resolve_safe_path(stat_file)
        fd = _wait_and_open_file(safe_path)
        try:
            file_stat = os.fstat(fd)
            if file_stat.st_size > MAX_FILE_SIZE:
                raise ValueError("Stat file exceeds maximum allowed size.")
            with io.open(fd, "r", encoding="utf-8") as f:
                return _parse_stat_lines(f)
        finally:
            os.close(fd)
    except (OSError, ValueError, FileNotFoundError) as exc:
        logger.error("Failed to read stat file.")
        raise RuntimeError("Unable to process statistics.") from exc

