class QuandlSpider(Spider):
    name = "quandl"
    allowed_domains = ["quandl.com"]

    def __init__(self, datasets: str = None, *args, **kwargs):
        super().__init__(*args, **kwargs)
        raw = datasets or ""
        self.datasets = [
            ds.strip()
            for ds in raw.split(",")
            if ds.strip() and self._is_valid_dataset_id(ds.strip())
        ]
        if not self.datasets:
            raise ValueError("No valid Quandl dataset identifiers provided")
        self._api_key = self._get_api_key()

    @staticmethod
    def _is_valid_dataset_id(dataset_id: str) -> bool:
        """
        Very strict validation: only alphanumeric characters,
        underscores, hyphens and forward slashes are allowed
        (e.g., "WIKI/PRICES").
        """
        pattern = re.compile(r'^[A-Za-z0-9_\-/]+$')
        return bool(pattern.fullmatch(dataset_id))

    @staticmethod
    def _get_api_key() -> str:
        """
        Retrieve Quandl API key from environment; never hard-code.
        """
        key = os.getenv("QUANDL_API_KEY")
        if not key:
            raise EnvironmentError("Quandl API key not configured in environment")
        return key

    def start_requests(self):
        for dataset in self.datasets:
            safe_dataset = urllib.parse.quote(dataset, safe="/")
            url = f"https://www.quandl.com/api/v3/datasets/{safe_dataset}.json"
            yield scrapy.Request(
                url=url,
                callback=self.parse,
                errback=self._handle_error,
                meta={"dataset": dataset},
                headers={"Accept": "application/json"},
                dont_filter=True,
                timeout=30,
            )

    def parse(self, response):
        dataset = response.meta.get("dataset")
        try:
            data = response.json()
        except Exception:
            self.logger.error(f"Failed to decode JSON for dataset {dataset}")
            return

        if not isinstance(data, dict) or "dataset" not in data:
            self.logger.error(f"Unexpected response structure for {dataset}")
            return

        try:
            dataset_info = data["dataset"]
            code = dataset_info.get("dataset_code", "")
            name = dataset_info.get("name", "")
            data_rows = dataset_info.get("data", [])
        except Exception:
            self.logger.exception(f"Error extracting fields for {dataset}")
            return

        if not isinstance(data_rows, list):
            self.logger.error(f"Data rows for {dataset} are not a list")
            data_rows = []

        code = self._sanitize_string(code)
        name = self._sanitize_string(name)

        item = MykgbItem()
        item["code"] = code
        item["name"] = name
        item["rows"] = data_rows

        self._store_in_db(code, name, data_rows)

        yield item

    def _store_in_db(self, code: str, name: str, rows: List[Any]):
        try:
            obj, created = Quandlset.objects.get_or_create(
                code=code,
                defaults={"name": name, "data": rows},
            )
            if not created:
                obj.name = name
                obj.data = rows
                obj.save(update_fields=["name", "data"])
