def _sanitize_string(
    value: Any,
    field_name: str,
    max_length: int = 256,
    pattern: Optional[re.Pattern] = None,
) -> str:
    if not isinstance(value, str):
        raise ValueError(f"{field_name} must be a string.")
    sanitized = value.strip()
    if len(sanitized) == 0 or len(sanitized) > max_length:
        raise ValueError(
            f"{field_name} length must be between 1 and {max_length} characters."
        )
    if pattern and not pattern.fullmatch(sanitized):
        raise ValueError(f"{field_name} contains invalid characters.")
    return sanitized


def _sanitize_amount(value: Any, field_name: str) -> float:
    try:
        amount = float(value)
    except (TypeError, ValueError):
        raise ValueError(f"{field_name} must be a numeric value.")
    if amount <= 0:
        raise ValueError(f"{field_name} must be greater than zero.")
    return amount


def _make_request(
    method: str,
    url: str,
    payload: Optional[Dict] = None,
    timeout: int = 10,
) -> Dict:
    headers = {
        "Authorization": f"Bearer {API_KEY}",
        "Content-Type": "application/json",
        "Accept": "application/json",
    }

    try:
        if method.upper() == "POST":
            response = requests.post(url, headers=headers, json=payload, timeout=timeout)
        elif method.upper() == "GET":
            response = requests.get(url, headers=headers, params=payload, timeout=timeout)
        else:
            raise ValueError("Unsupported HTTP method.")
        response.raise_for_status()
        return response.json()
    except (Timeout, HTTPError, RequestException) as exc:
        raise CoinbaseAPIError("Failed to communicate with Coinbase API.") from exc


class CoinbaseAPIError(Exception):
    """Custom exception for Coinbase API errors without leaking sensitive data."""
    pass


def create_order(
    product_id: str,
    side: str,
    size: float,
    price: Optional[float] = None,
) -> Order:
    product_id = _sanitize_string(
        product_id, "product_id", pattern=PRODUCT_ID_PATTERN
    )
    side = _sanitize_string(side, "side", max_length=4).lower()
    if side not in {"buy", "sell"}:
        raise ValueError("side must be either 'buy' or 'sell'.")
    size = _sanitize_amount(size, "size")
    if price is not None:
        price = _sanitize_amount(price, "price")

    payload = {
        "product_id": product_id,
        "side": side,
        "size": str(size),
    }
