import os
import json
import logging
import re
import pathlib
import nltk

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler()],
)

BASE_INDEX_ROOT = (pathlib.Path.cwd() / "indexes").resolve()
BASE_INDEX_ROOT.mkdir(parents=True, exist_ok=True)

TOKEN_PATTERN = re.compile(r" \w+ ")
MAX_TOKENS = 100_000
MAX_DOC_SIZE = 1_000_000


class SecureIndexer:
    def __init__(self):
        self.inverted_index: dict[str, list[tuple[int, int]]] = {}
        self.forward_index: dict[str, list[str]] = {}
        self._stemmer = nltk.PorterStemmer()
        self._index_path: pathlib.Path | None = None

    def _load_json(self, file_path: pathlib.Path) -> dict:
        if file_path.is_file():
            try:
                with file_path.open("r", encoding="utf-8") as f:
                    return json.load(f)
            except Exception:
                logging.exception("Failed to load JSON from %s", file_path)
        return {}

    def _save_json(self, data: dict, file_path: pathlib.Path) -> None:
        tmp_path = file_path.with_suffix(".tmp")
        flags = os.O_CREAT | os.O_EXCL | os.O_WRONLY
        if hasattr(os, "O_NOFOLLOW"):
            flags |= os.O_NOFOLLOW
        fd = os.open(tmp_path, flags, 0o600)
        try:
            with os.fdopen(fd, "w", encoding="utf-8") as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
            os.replace(tmp_path, file_path)
        finally:
            try:
                os.unlink(tmp_path)
            except FileNotFoundError:
                pass

    def startIndexer(self, indexDir: str) -> None:
        try:
            if not isinstance(indexDir, str):
                raise ValueError("Index directory must be a string")

            user_path = pathlib.Path(indexDir).resolve()
            safe_dir = (BASE_INDEX_ROOT / user_path.relative_to(user_path.anchor)).resolve()

            if not safe_dir.is_relative_to(BASE_INDEX_ROOT):
                raise ValueError("Index directory must reside within the allowed base directory")
            if safe_dir.is_symlink():
                raise ValueError("Index directory must not be a symlink")

            safe_dir.mkdir(parents=True, exist_ok=True)
            # Reâresolve after creation to ensure no symlink was introduced
            safe_dir = safe_dir.resolve()
            if not safe_dir.is_relative_to(BASE_INDEX_ROOT):
                raise ValueError("Resolved index directory escaped the base directory")
            if safe_dir.is_symlink():
                raise ValueError("Resolved index directory is a symlink")

            self._index_path = safe_dir

            inverted_path = safe_dir / "invertedIndex.json"
            forward_path = safe_dir / "forwardIndex.json"

            self.inverted_index = self._load_json(inverted_path)
            self.forward_index = self._load_json(forward_path)

        except Exception:
            logging.exception("Failed to initialise indexer")
            raise

    def add_document(self, doc_id: int, raw_text: str) -> None:
        try:
            if not isinstance(doc_id, int) or doc_id < 0:
                raise ValueError("Document ID must be a nonânegative integer")
            if not isinstance(raw_text, str):
                raise ValueError("Document text must be a string")
            if len(raw_text) > MAX_DOC_SIZE:
                raise ValueError("Document text exceeds size limits")

            tokens = TOKEN_PATTERN.findall(raw_text.lower())
            if len(tokens) > MAX_TOKENS:
                raise ValueError("Document contains too many tokens")
            stems = [self._stemmer.stem(tok) for tok in tokens if tok]

            self.forward_index[str(doc_id)] = stems

            for position, term in enumerate(stems):
                postings = self.inverted_index.get(term, [])
                postings.append((position, doc_id))
                self.inverted_index[term] = postings

        except Exception:
            logging.exception("Error adding document")
            raise

    def search(self, query: str) -> set[int]:
        try:
            if not isinstance(query, str):
                raise ValueError("Query must be a string")
            if len(query) > 200:
                raise ValueError("Query exceeds length limits")

            tokens = TOKEN_PATTERN.findall(query.lower())
            stems = [self._stemmer.stem(tok) for tok in tokens if tok]

            result_sets: list[set[int]] = []
            for stem in stems:
                postings = self.inverted_index.get(stem, [])
                doc_ids = {doc_id for _, doc_id in postings}
                result_sets.append(doc_ids)

            if not result_sets:
                return set()
            return set.intersection(*result_sets)

        except Exception:
            logging.exception("Search operation failed")
            return set()

    def close(self) -> None:
        try:
            if self._index_path is None:
                return

            inverted_path = self._index_path / "invertedIndex.json"
            forward_path = self._index_path / "forwardIndex.json"

            self._save_json(self.inverted_index, inverted_path)
            self._save_json(self.forward_index, forward_path)

        except Exception:
            logging.exception("Failed to close index files")

