logger = logging.getLogger(__name__)

DEFAULT_BASE_DIR = '/var/monitor'
BASE_DIR = os.getenv('MONITOR_BASE_DIR', DEFAULT_BASE_DIR)

if not isinstance(BASE_DIR, str):
    raise RuntimeError('Invalid MONITOR_BASE_DIR configuration')
if not os.path.isabs(BASE_DIR):
    raise RuntimeError('BASE_DIR must be an absolute path')
if not os.path.isdir(BASE_DIR):
    raise RuntimeError('BASE_DIR does not exist or is not a directory')
BASE_DIR = os.path.realpath(BASE_DIR)

try:
    ALERT_SECONDS = int(os.getenv('ALERT_THRESHOLD_SECONDS', '3600'))
    if ALERT_SECONDS < 0:
        raise ValueError()
except Exception:
    ALERT_SECONDS = 3600

def _is_path_allowed(path: str) -> bool:
    try:
        real_path = os.path.realpath(path)
    except Exception:
        return False
    try:
        return os.path.commonpath([real_path, BASE_DIR]) == BASE_DIR
    except ValueError:
        return False

def _sanitize_path_for_log(path: str) -> str:
    return os.path.basename(path)

def check(path):
    """Check whether the file's modification time exceeds the alert threshold."""
    if not isinstance(path, str):
        logger.warning("Invalid path type supplied")
        return False

    if not _is_path_allowed(path):
        logger.warning("Path validation failed for %s", _sanitize_path_for_log(path))
        return False

    real_path = os.path.realpath(path)

    try:
        stat_result = os.stat(real_path)
    except FileNotFoundError:
        logger.info("File not found: %s", _sanitize_path_for_log(path))
        return False
    except PermissionError:
        logger.warning("Permission denied accessing %s", _sanitize_path_for_log(path))
        return False
    except OSError:
        logger.error("Unable to access %s", _sanitize_path_for_log(path))
        return False

    mtime = datetime.fromtimestamp(stat_result.st_mtime, tz=timezone.utc)
    now = datetime.now(timezone.utc)
    elapsed = (now - mtime).total_seconds()

    if elapsed > ALERT_SECONDS:
        logger.warning(
            "Alert: %s exceeds threshold (elapsed %s seconds)",
            _sanitize_path_for_log(path),
            int(elapsed)
        )
        return True

    return False

