def is_allowed_literal(value) -> bool:
    """Whitelist check for allowed literal types and size."""
    if isinstance(value, (int, float, bool, type(None))):
        return True
    if isinstance(value, str):
        return len(value) <= MAX_STRING_LENGTH
    return False

def main() -> None:
    command = read_command()

    if not command:
        print("Empty command.", file=sys.stderr)
        sys.exit(1)

    if len(command) > MAX_COMMAND_LENGTH:
        print("Command too long.", file=sys.stderr)
        sys.exit(1)

    try:
        result = ast.literal_eval(command)
    except (ValueError, SyntaxError, RecursionError):
        print("Invalid command input; only literal expressions are allowed.", file=sys.stderr)
        sys.exit(1)

    if not is_allowed_literal(result):
        print("Unsupported or oversized literal.", file=sys.stderr)
        sys.exit(1)

    print(result)

