from os import getenv
from itsdangerous import URLSafeTimedSerializer, BadSignature, SignatureExpired
from werkzeug.security import generate_password_hash, check_password_hash
import redis

logging.basicConfig(level=logging.ERROR)

_USERNAME_REGEX = re.compile(r'^[a-zA-Z0-9_.-]{3,30}$')
_MAX_PASSWORD_LENGTH = 256

_TOKEN_SECRET = getenv('APP_TOKEN_SECRET')
if not _TOKEN_SECRET:
    raise RuntimeError('Environment variable APP_TOKEN_SECRET must be set')

_serializer = URLSafeTimedSerializer(_TOKEN_SECRET, salt='auth-token-salt')


class UserError(Exception):
    """Base class for user related errors without leaking internal info."""
    pass


class InvalidUsernameError(UserError):
    pass


class InvalidPasswordError(UserError):
    pass


def _sanitize_input(value: str) -> str:
    """Strip leading/trailing whitespace and ensure the value is a string."""
    if not isinstance(value, str):
        raise ValueError("Input must be a string")
    return value.strip()


def _validate_username(username: str) -> None:
    """Validate username against allowed pattern."""
    if not _USERNAME_REGEX.fullmatch(username):
        raise InvalidUsernameError("Username does not meet requirements")


def _hash_password(password: str) -> str:
    """Generate a strong password hash."""
    return generate_password_hash(password, method='pbkdf2:sha256', salt_length=16)


def _verify_password_hash(stored_hash: str, password: str) -> bool:
    """Constant-time password verification."""
    return check_password_hash(stored_hash, password)


class User(object):
    def __init__(self, username: str = ""):
        self.username = ""
        if username:
            self.set_username(username)
        self.password_hash = None  # type: str | None

    def set_username(self, username: str) -> None:
        username = _sanitize_input(username)
        _validate_username(username)
        self.username = username

    def set_password(self, password: str) -> None:
        password = _sanitize_input(password)
        if len(password) < 8:
            raise InvalidPasswordError("Password must be at least 8 characters")
        if len(password) > _MAX_PASSWORD_LENGTH:
            raise InvalidPasswordError(f"Password must not exceed {_MAX_PASSWORD_LENGTH} characters")
        self.password_hash = _hash_password(password)

    def check_password(self, password: str) -> bool:
        if self.password_hash is None:
            return False
        password = _sanitize_input(password)
        return _verify_password_hash(self.password_hash, password)

    def generate_auth_token(self, expiration: int = 3600) -> str:
        """Return a signed authentication token."""
        if not self.username:
            raise UserError("Cannot generate token for user without username")
        data = {'username': self.username}
        token = _serializer.dumps(data)
        return token

    @classmethod
    def verify_auth_token(cls, token: str, max_age: int = 3600) -> str | None:
        """Validate token and return username if valid."""
        try:
            data = _serializer.loads(token, max_age=max_age)
            username = data.get('username')
            if isinstance(username, str) and _USERNAME_REGEX.fullmatch(username):
                return username
        except (BadSignature, SignatureExpired):
            return None
        return None

    def to_dict(self) -> dict:
        """Serialize user data for storage."""
        if not self.username:
            raise UserError("User must have a username before serialization")
        if not self.password_hash:
            raise UserError("User must have a password set before serialization")
        return {
            'username': self.username,
            'password_hash': self.password_hash
        }

    def save(self) -> None:
        """Persist user data to Redis using a namespaced key."""
        try:
            key = f"user:{self.username}"
            redis_db.set(key, json.dumps(self.to_dict()))
        except redis.exceptions.ConnectionError as e:
            logging.exception("Redis connection error while saving user")
            raise UserError("Failed to save user") from e
        except (TypeError, ValueError) as e:
            logging.exception("Serialization error while saving user")
            raise UserError("Failed to save user") from e
        except Exception as e:
            logging.exception("Unexpected error while saving user")
            raise UserError("Failed to save user") from e

    @classmethod
    def load(cls, username: str) -> 'User':
        """Load a user from Redis; returns a User instance or raises UserError."""
        username = _sanitize_input(username)
        _validate_username(username)
        try:
            key = f"user:{username}"
            raw = redis_db.get(key)
            if raw is None:
                raise UserError("User not found")
            data = json.loads(raw)
            user = cls(username=data.get('username', ''))
            user.password_hash = data.get('password_hash')
            return user
        except redis.exceptions.ConnectionError as e:
            logging.exception("Redis connection error while loading user")
            raise UserError("Failed to load user") from e
        except json.JSONDecodeError as e:
            raise UserError("Corrupted user data") from e
        except Exception as e:
            logging.exception("Unexpected error while loading user")
            raise UserError("Failed to load user") from e

