def _get_base_dir() -> Path:
    env_path = os.getenv("STAGING_BASE_DIR")
    base = Path(env_path) if env_path else Path("/var/app/staging")
    if not base.is_absolute():
        raise ValueError("Base staging directory must be an absolute path")
    try:
        base.mkdir(mode=0o750, parents=True, exist_ok=True)
    except Exception as e:
        raise RuntimeError(f"Cannot create base staging directory: {e}")
    return base.resolve()

_BASE_DIR = _get_base_dir()

def _is_subpath(child: Path, parent: Path) -> bool:
    try:
        child_resolved = child.resolve(strict=True)
        parent_resolved = parent.resolve(strict=True)
        child_resolved.relative_to(parent_resolved)
        return True
    except (ValueError, FileNotFoundError):
        return False

def _validate_url(url: str) -> str:
    allowed_schemes = {"http", "https", "svn"}
    parsed = urllib.parse.urlparse(url)

    if parsed.scheme.lower() not in allowed_schemes:
        raise ValueError("Disallowed URL scheme")

    if "@" in parsed.netloc:
        raise ValueError("Credentials must not be embedded in URL")

    if parsed.query or parsed.fragment:
        raise ValueError("URL must not contain query or fragment components")

    if not re.fullmatch(r"[/A-Za-z0-9._~%\-]*", parsed.path):
        raise ValueError("URL contains invalid characters")

    for segment in (seg for seg in parsed.path.split("/") if seg):
        if segment.startswith("--"):
            raise ValueError("URL path segment cannot start with '--'")

    # Reâassemble to ensure consistent formatting
    return urllib.parse.urlunparse(parsed)

def export_svn(url: str, stagingFolder: str, verbose: bool = False) -> bool:
    if not isinstance(url, str) or not url.strip():
        raise ValueError("Invalid URL")
    if not isinstance(stagingFolder, str) or not stagingFolder.strip():
        raise ValueError("Invalid staging folder")

    sanitized_url = _validate_url(url)

    staging_path = Path(stagingFolder).expanduser().resolve()
    try:
        staging_path.mkdir(mode=0o750, parents=True, exist_ok=True)
    except Exception as e:
        raise RuntimeError(f"Failed to create staging directory: {e}")

    if not _is_subpath(staging_path, _BASE_DIR):
        raise RuntimeError("Staging folder is outside the allowed base directory")

    # Verify write permission atomically
    try:
        test_file = staging_path / ".write_test"
        with open(test_file, "w") as f:
            f.write("test")
        test_file.unlink()
    except Exception as e:
        raise PermissionError(f"Cannot write to staging folder: {e}")

    try:
        result = subprocess.run(
            [_SVN_BINARY, "export", sanitized_url, ".", "--force"],
            cwd=str(staging_path),
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            env=_SUBPROCESS_ENV,
            check=False,
        )
    except Exception as e:
        raise RuntimeError(f"Failed to invoke svn: {e}")

    if result.returncode != 0:
        if verbose:
            sys.stderr.write(f"svn export failed: {result.stderr.strip()}
")
        raise RuntimeError(f"Package export failed: {result.stderr.strip()}")

    if verbose:
