BASE_DIR = pathlib.Path("/var/app/data").resolve()


def _is_path_within_base(resolved_path: str) -> bool:
    """
    Verify that the given absolute path is inside BASE_DIR.
    """
    try:
        # Resolve any remaining symlinks via /proc/self/fd mechanism
        return pathlib.Path(resolved_path).is_relative_to(BASE_DIR)
    except AttributeError:
        # For Python < 3.9 fallback
        try:
            pathlib.Path(resolved_path).relative_to(BASE_DIR)
            return True
        except ValueError:
            return False


def sha256_hex_file(
    filepath: Union[str, pathlib.Path],
    max_bytes: Optional[int] = None,
) -> str:
    """
    Returns the SHA256 of a given file in hexadecimal.

    Args:
        filepath: Path to the file as a string or pathlib.Path.
        max_bytes: Optional maximum number of bytes to read from the file.

    Returns:
        Hexadecimal SHA256 digest of the file content.

    Raises:
        TypeError: If arguments have invalid types.
        ValueError: If max_bytes is negative or filepath is empty.
        PermissionError: If the file is outside the allowed directory,
                         is not a regular file, or is a symlink.
        IOError: If an error occurs while reading the file.
    """
    # ---------- Input validation ----------
    if isinstance(filepath, str):
        if not filepath:
            raise ValueError("filepath must not be empty")
        path_str = filepath
    elif isinstance(filepath, pathlib.Path):
        path_str = str(filepath)
    else:
        raise TypeError("filepath must be a string or pathlib.Path")

    if max_bytes is not None:
        if not isinstance(max_bytes, int):
            raise TypeError("max_bytes must be an integer or None")
        if max_bytes < 0:
            raise ValueError("max_bytes must be non-negative")

    # ---------- Secure open ----------
    flags = os.O_RDONLY | os.O_NOFOLLOW | os.O_CLOEXEC
    try:
        fd = os.open(path_str, flags)
    except OSError as exc:
        # ELOOP indicates a symlink encountered
        if getattr(exc, "errno", None) == getattr(os, "ELOOP", 0):
            raise PermissionError("Access to symlinks is prohibited") from exc
        raise PermissionError("Unable to access the requested file") from exc

    try:
        # Verify the opened file descriptor points inside BASE_DIR
        try:
            real_path = os.readlink(f"/proc/self/fd/{fd}")
        except OSError:
            # Fallback if /proc is not available; use fstat to compare device/inode with BASE_DIR
            raise PermissionError("Unable to verify file location")

        if not _is_path_within_base(real_path):
            raise PermissionError("Access to paths outside the allowed directory is prohibited")

        # Verify the file is a regular file
        file_stat = os.fstat(fd)
        if not stat.S_ISREG(file_stat.st_mode):
            raise PermissionError("File is not a regular file")

        # ---------- Compute hash ----------
        hasher = hashlib.sha256()
        buffer_size = 8192  # 8 KiB

        with os.fdopen(fd, "rb") as f:
            remaining = max_bytes
            while True:
                if remaining is None:
                    chunk = f.read(buffer_size)
                else:
                    to_read = min(buffer_size, remaining)
                    if to_read <= 0:
                        break
                    chunk = f.read(to_read)
                    remaining -= len(chunk)

                if not chunk:
                    break
                hasher.update(chunk)

        return hasher.hexdigest()
    except OSError as exc:
        raise IOError("Error processing the file") from exc
    finally:
        # Ensure the descriptor is closed if it hasn't been closed by fdopen
        try:
            os.close(fd)
        except OSError:
            pass

