def _drop_privileges():
    """Drop privileges to the nobody user (POSIX only). Abort if it fails."""
    if os.name != "posix":
        return
    if os.geteuid() != 0:
        return  # Not running as root, nothing to drop
    import pwd
    try:
        nobody = pwd.getpwnam("nobody")
        os.setgid(nobody.pw_gid)
        os.setuid(nobody.pw_uid)
        if os.getuid() != nobody.pw_uid or os.getgid() != nobody.pw_gid:
            raise RuntimeError("Privilege drop verification failed")
    except Exception as e:
        raise RuntimeError(f"Failed to drop privileges: {e}") from e


def _preexec():
    """Preâexec function to close fds, start new session and drop privileges."""
    # Close all file descriptors except stdin/stdout/stderr (0,1,2)
    try:
        max_fd = os.sysconf("SC_OPEN_MAX")
    except (AttributeError, ValueError):
        max_fd = 256
    os.closerange(3, max_fd)
