    Recreate a reader instance from a JSONâcompatible dictionary.
    Performs strict validation and sanitization of all inputs.
    """
    import os
    import re
    import string
    import urllib.parse

    if not isinstance(state, dict):
        raise ValueError("Invalid state: expected a dict")

    required_fields = {
        "shard_filenames": list,
        "buffer_size": int,
        "account_id": (str, type(None)),
        "delimiter": str,
        "fail_on_missing_input": bool,
    }

    for field, expected_type in required_fields.items():
        if field not in state:
            raise ValueError(f"Missing required field: {field}")
        if not isinstance(state[field], expected_type):
            raise ValueError(f"Invalid type for field {field}")

