    if len(shard_names) > MAX_FILES:
        raise ValueError(f"Too many shard filenames (max {MAX_FILES})")

    delimiter = state["delimiter"]
    allowed_delimiters = set(string.ascii_letters + string.digits + string.punctuation)
    if (
        not isinstance(delimiter, str)
        or len(delimiter) != 1
        or delimiter not in allowed_delimiters
    ):
        raise ValueError("Invalid delimiter")

    sanitized_filenames = []
    native_sep = os.sep
    alt_sep = '/' if native_sep == '\' else '\'

    for raw_name in shard_names:
        if not isinstance(raw_name, str):
            raise ValueError("All shard filenames must be strings")
        if len(raw_name) > MAX_FILENAME_LEN:
            raise ValueError(
                f"Shard filename too long (max {MAX_FILENAME_LEN} characters)"
            )

        decoded_name = urllib.parse.unquote(raw_name)

        if "�" in decoded_name:
            raise ValueError(f"Invalid shard filename (null byte): {raw_name}")

        if alt_sep in decoded_name:
            raise ValueError(
                f"Invalid shard filename (alternate separator): {raw_name}"
            )

        norm = os.path.normpath(decoded_name)

        if os.path.isabs(norm):
            raise ValueError(f"Invalid shard filename (absolute path): {raw_name}")

        if re.match(r'^[A-Za-z]:', norm):
            raise ValueError(f"Invalid shard filename (drive letter): {raw_name}")

        if any(part == ".." for part in norm.split(native_sep)):
            raise ValueError(f"Invalid shard filename (path traversal): {raw_name}")

        sanitized_filenames.append(norm)

    buffer_size = state["buffer_size"]
    if not (0 < buffer_size <= 10 * 1024 * 1024):
        raise ValueError("buffer_size must be > 0 and <= 10â¯MiB")

    instance = cls(
        sanitized_filenames,
        buffer_size=buffer_size,
        _account_id=state.get("account_id"),
        delimiter=delimiter,
    )
    instance._fail_on_missing_input = state["fail_on_missing_input"]
    return instance

