# Configuration
ALLOWED_EXECUTABLE_DIR = Path("/opt/allowed_bins").resolve()
SAFE_ENV_VARS = {"HOME", "USER", "LANG", "LC_ALL"}
SAFE_PATH = "/usr/bin:/bin"
EXECUTION_TIMEOUT = 30  # seconds
MAX_OUTPUT_BYTES = 1_000_000  # 1 MB
MEMORY_LIMIT_BYTES = 200 * 1024 * 1024  # 200 MiB

logger = logging.getLogger(__name__)

def _is_executable(p: Path) -> bool:
    st = p.stat()
    if st.st_mode & (stat.S_ISUID | stat.S_ISGID):
        return False
    return bool(st.st_mode & 0o111)

def _sanitize_path(path_str: str) -> str:
    """
    Resolve the given path, ensure it exists, is a regular file,
    resides under ALLOWED_EXECUTABLE_DIR, and is executable.
    """
    p = Path(path_str).expanduser().resolve(strict=True)
    try:
        if not p.is_file():
            raise ValueError
        if not p.is_relative_to(ALLOWED_EXECUTABLE_DIR):
            raise ValueError
        if not _is_executable(p):
            raise ValueError
    except Exception as exc:
        raise ValueError(f"Invalid executable path: {path_str}") from exc
    return str(p)

def _build_safe_env(user_env):
    """
    Start from a minimal safe baseline and merge whitelisted variables
    from user-provided mapping.
    """
    base_env = {k: v for k, v in os.environ.items() if k in SAFE_ENV_VARS}
    base_env["PATH"] = SAFE_PATH
    if user_env:
        for k, v in user_env.items():
            if k in SAFE_ENV_VARS:
                base_env[str(k)] = str(v)
    return base_env

def _apply_rlimits():
    # Limit virtual memory, with fallbacks
    try:
        resource.setrlimit(resource.RLIMIT_AS, (MEMORY_LIMIT_BYTES, MEMORY_LIMIT_BYTES))
    except (ValueError, resource.error):
        resource.setrlimit(resource.RLIMIT_DATA, (MEMORY_LIMIT_BYTES, MEMORY_LIMIT_BYTES))
    # Limit resident set size as additional safeguard
    if hasattr(resource, "RLIMIT_RSS"):
        try:
            resource.setrlimit(resource.RLIMIT_RSS, (MEMORY_LIMIT_BYTES, MEMORY_LIMIT_BYTES))
        except resource.error:
            pass
    # Limit CPU time
    cpu_limit = EXECUTION_TIMEOUT + 5
    resource.setrlimit(resource.RLIMIT_CPU, (cpu_limit, cpu_limit))

