        stderr_chunks = []
        stdout_len = 0
        stderr_len = 0
        start_time = time.time()
        fds = {stdout_r, stderr_r}
        while fds:
            elapsed = time.time() - start_time
            remaining = max(0, EXECUTION_TIMEOUT - elapsed)
            if remaining == 0:
                try:
                    os.kill(pid, signal.SIGKILL)
                except ProcessLookupError:
                    pass
                break
            rlist, _, _ = select.select(fds, [], [], remaining)
            if not rlist:
