                        to_take = min(len(data), MAX_OUTPUT_BYTES - stdout_len)
                        stdout_chunks.append(data[:to_take])
                        stdout_len += to_take
                else:
                    if stderr_len < MAX_OUTPUT_BYTES:
                        to_take = min(len(data), MAX_OUTPUT_BYTES - stderr_len)
                        stderr_chunks.append(data[:to_take])
                        stderr_len += to_take

        _, status = os.waitpid(pid, 0)
        if os.WIFEXITED(status):
            returncode = os.WEXITSTATUS(status)
        elif os.WIFSIGNALED(status):
            returncode = -os.WTERMSIG(status)
        else:
            returncode = -1

        stdout_bytes = b"".join(stdout_chunks)
        stderr_bytes = b"".join(stderr_chunks)

        stdout_str = stdout_bytes.decode("utf-8", errors="replace")
        stderr_str = stderr_bytes.decode("utf-8", errors="replace")
        if len(stdout_str) == MAX_OUTPUT_BYTES:
            stdout_str += "
[Truncated]"
        if len(stderr_str) == MAX_OUTPUT_BYTES:
            stderr_str += "
[Truncated]"

        logger.info("Command exited with return code %s", returncode)
        if logger.isEnabledFor(logging.DEBUG):
            logger.debug("Stdout: %s", stdout_str.strip())
            logger.debug("Stderr: %s", stderr_str.strip())

        class Result:
            pass

        result = Result()
        result.stdout = stdout_str
        result.stderr = stderr_str
        result.returncode = returncode
        return result

