def _is_path_within_base(path: Path, base: Path) -> bool:
    try:
        return path.is_relative_to(base)  # Python 3.9+
    except AttributeError:
        return base in path.parents or path == base


def _reject_symlinks(path: Path) -> bool:
    """Return True if the path itself or any ancestor is a symlink."""
    if path.is_symlink():
        return True
    for parent in path.parents:
        if parent.is_symlink():
            return True
    return False


def _has_symlink_in_tree(root: Path) -> bool:
    """Return True if any entry inside the directory tree is a symlink."""
    try:
        for p in root.rglob("*"):
            if p.is_symlink():
                return True
    except Exception as e:
        logging.error(f"Error while scanning for symlinks in {root}: {e}")
        return True
    return False


def _apply_recursive_mode(root: Path, mode: int):
    """Apply permissions recursively without following symlinks."""
    for dirpath, dirnames, filenames in os.walk(root, followlinks=False):
        for name in dirnames + filenames:
            target = os.path.join(dirpath, name)
            try:
                os.chmod(target, mode, follow_symlinks=False)
            except Exception as e:
                logging.error(f"Failed to set mode on {target}: {e}")
                raise
    try:
        os.chmod(root, mode, follow_symlinks=False)
    except Exception as e:
        logging.error(f"Failed to set mode on root {root}: {e}")
        raise


def copy_artifacts(source_path: str, destination_path: str) -> bool:
    """
    Securely moves a directory of artifacts from source_path to destination_path.
    Returns True on success, False otherwise.
    """
    try:
        # Resolve without following symlinks to keep symlink checks meaningful
        src = Path(source_path).expanduser().resolve(strict=False)
        dst = Path(destination_path).expanduser().resolve(strict=False)

        if not src.is_absolute() or not dst.is_absolute():
            logging.error("Source and destination must be absolute paths.")
            return False

        # Source must exist and be a directory (after resolving real path)
        if not src.exists():
            logging.error("Source path does not exist.")
            return False
        if not src.is_dir():
            logging.error("Source path is not a directory.")
            return False

        # Validate source location
        if not _is_path_within_base(src, SAFE_BASE_DIR):
            logging.error("Source path is outside the allowed base directory.")
            return False

        # Symlink checks on source
        if _reject_symlinks(src) or _has_symlink_in_tree(src):
            logging.error("Source directory contains symlinks, which are not allowed.")
            return False

        if src == dst:
            logging.error("Source and destination are identical.")
            return False

        # Destination base check (using resolved parent)
        dst_parent_resolved = dst.parent.resolve()
        if not _is_path_within_base(dst_parent_resolved, SAFE_BASE_DIR):
            logging.error("Destination path is outside the allowed directory.")
            return False

        # Ensure destination does not already exist
        if dst.exists():
            logging.error("Destination already exists.")
            return False

        # Create destination parent with restrictive permissions atomically
        try:
            os.makedirs(dst.parent, mode=0o700, exist_ok=True)
            os.chmod(dst.parent, 0o700, follow_symlinks=False)
        except OSError as e:
            logging.error(f"Failed to prepare destination parent directory: {e}")
            return False

