    SESSION_COOKIE_SECURE=True,
    SESSION_COOKIE_SAMESITE="Lax",
    SERVER_NAME=os.getenv("SERVER_NAME", None),
    TRUSTED_HOSTS=[os.getenv("TRUSTED_HOST", "localhost")],
    BASE_URL=os.getenv("BASE_URL", "https://example.com"),
)

# CSRF protection
csrf = CSRFProtect(app)

# Rate limiting
limiter = Limiter(key_func=get_remote_address, app=app)

# PayPal SDK configuration â use environment variables for secrets
paypalrestsdk.configure(
    {
        "mode": os.getenv("PAYPAL_MODE", "sandbox"),
        "client_id": os.getenv("PAYPAL_CLIENT_ID", ""),
        "client_secret": os.getenv("PAYPAL_CLIENT_SECRET", ""),
        "log_level": "INFO",
    }
)


def _is_valid_amount(value):
    """
    Validate that the amount is a positive decimal with at most two fractional digits.
    """
    try:
        dec = Decimal(str(value).strip())
        dec = dec.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
        return dec > 0
    except (InvalidOperation, TypeError, ValueError):
        return False


def _sanitize_currency(currency):
    """
    Accept only ISO 4217 threeâletter currency codes.
    """
    if not isinstance(currency, str):
        return None
    currency = currency.strip().upper()
    if len(currency) != 3 or not currency.isalpha():
        return None
    whitelist = os.getenv("ALLOWED_CURRENCIES")
    if whitelist:
        allowed = {c.strip().upper() for c in whitelist.split(",")}
    else:
        allowed = {"USD", "EUR", "GBP", "CAD", "AUD", "JPY"}
    return currency if currency in allowed else None


@app.before_request
def enforce_https_and_json_csrf():
    # Enforce HTTPS (skip for local development)
    if (
        not request.is_secure
        and app.env != "development"
        and not request.host.startswith("localhost")
        and not request.host.startswith("127.0.0.1")
    ):
        url = request.url.replace("http://", "https://", 1)
        return redirect(url, code=301)

    # CSRF protection for JSON POST to /pay
    if request.path == "/pay" and request.method == "POST" and request.is_json:
        token = request.headers.get("X-CSRFToken") or request.headers.get("X-CSRF-Token")
        if not token:
            return "Missing CSRF token", 400
        try:
            validate_csrf(token)
        except Exception:
            return "Invalid CSRF token", 400


@app.after_request
def set_security_headers(response):
    response.headers.setdefault("X-Frame-Options", "DENY")
    response.headers.setdefault("X-Content-Type-Options", "nosniff")
    response.headers.setdefault("Referrer-Policy", "same-origin")
    response.headers.setdefault("Content-Security-Policy", "default-src 'self'")
    response.headers.setdefault(
        "Strict-Transport-Security", "max-age=31536000; includeSubDomains"
    )
    response.headers.setdefault("X-XSS-Protection", "1; mode=block")
    return response


@app.errorhandler(CSRFError)
def handle_csrf_error(e):
    flash("Invalid CSRF token.", "error")
    return redirect(url_for("index")), 400


@app.route("/", methods=["GET"])
def index():
    return render_template("index.html")


@app.route("/pay", methods=["POST"])
@limiter.limit("5 per minute")
def create_payment():
    """
    Create a PayPal payment after validating and sanitising user input.
    Expected JSON payload:
    {
        "amount": "10.00",
        "currency": "USD",
        "description": "Order #1234"
    }
    """
    if not request.is_json:
        flash("Invalid request format.", "error")
        return redirect(url_for("index")), 400

    data = request.get_json(silent=True) or {}
    amount_raw = data.get("amount")
    currency_raw = data.get("currency")
    description_raw = data.get("description", "").strip()

    # Validate amount
    if not _is_valid_amount(amount_raw):
        flash("Invalid amount.", "error")
        return redirect(url_for("index")), 400
    amount_decimal = Decimal(str(amount_raw)).quantize(
        Decimal("0.01"), rounding=ROUND_HALF_UP
    )
    amount_str = f"{amount_decimal:.2f}"

    # Validate currency
    currency = _sanitize_currency(currency_raw)
    if not currency:
        flash("Unsupported currency.", "error")
        return redirect(url_for("index")), 400

    # Description sanitisation â strip HTML and limit length
    if len(description_raw) > 255:
        flash("Description too long.", "error")
        return redirect(url_for("index")), 400
    description = bleach.clean(description_raw, tags=[], strip=True)

    base_url = app.config["BASE_URL"].rstrip("/")
    payment = paypalrestsdk.Payment(
        {
            "intent": "sale",
            "payer": {"payment_method": "paypal"},
            "transactions": [
                {
                    "amount": {"total": amount_str, "currency": currency},
                    "description": description,
                }
            ],
            "redirect_urls": {
                "return_url": f"{base_url}{url_for('execute_payment')}",
                "cancel_url": f"{base_url}{url_for('index')}",
            },
        }
    )

    if not payment.create():
        err = payment.error if isinstance(payment.error, dict) else {}
        safe_err = {"name": err.get("name"), "message": err.get("message")}
        app.logger.error("PayPal payment creation failed: %s", safe_err)
        flash("Unable to process payment at this time.", "error")
        return redirect(url_for("index")), 502

    session["payment_id"] = payment.id

    for link in payment.links:
        if link.rel == "approval_url":
            return redirect(link.href)

    flash("Approval URL not found.", "error")
    return redirect(url_for("index")), 500


@app.route("/execute", methods=["GET"])
def execute_payment():
    """
    Complete the PayPal payment after the user approves it.
    """
    payment_id = session.pop("payment_id", None)
    payer_id = request.args.get("PayerID")
    token = request.args.get("token")

    if not payment_id or not payer_id or not token:
        flash("Invalid payment execution request.", "error")
        return redirect(url_for("index")), 400

    payment = paypalrestsdk.Payment.find(payment_id)

    if payment.execute({"payer_id": payer_id}):
        flash("Payment completed successfully.", "success")
        return render_template("success.html", payment=payment.to_dict())
    else:
        err = payment.error if isinstance(payment.error, dict) else {}
        safe_err = {"name": err.get("name"), "message": err.get("message")}
        app.logger.error("PayPal payment execution failed: %s", safe_err)
        flash("Payment could not be completed.", "error")
        return redirect(url_for("index")), 502


