MAX_PASSWORD_LEN = 128
MAX_EXTRA_ARGS_LEN = 256
MAX_IP_STR_LEN = 45  # IPv6 max length

# Safe character whitelist for configurable string fields (no path separators)
SAFE_STR_PATTERN = re.compile(r'^[A-Za-z0-9._+\-=:]+$')


def _is_valid_ip(ip):
    if not isinstance(ip, str) or len(ip) > MAX_IP_STR_LEN:
        return False
    try:
        ipaddress.ip_address(ip)
        return True
    except ValueError:
        return False


def _is_allowed_cli_path(path):
    """Validate that the CLI path is absolute, resolves to a real location,
    is whitelisted, owned by root, executable, nonâwritable by group/others,
    and is a regular file."""
    if not isinstance(path, str) or not os.path.isabs(path):
        return False
    real_path = os.path.realpath(path)
    allowed = {
        "/opt/emc/cli/naviseccli",
        "/usr/local/bin/naviseccli",
    }
    if real_path not in allowed:
        return False
    try:
        st = os.stat(real_path)
    except OSError:
        return False
    # Must be a regular file
    if not stat.S_ISREG(st.st_mode):
        return False
    # Must be owned by root (uid 0)
    if st.st_uid != 0:
        return False
    # Must have at least one executable bit set
    if not (st.st_mode & (stat.S_IXUSR | stat.S_IXGRP | stat.S_IXOTH)):
        return False
    # Must not be writable by group or others
    if st.st_mode & (stat.S_IWGRP | stat.S_IWOTH):
        return False
    return True


