    return (
        isinstance(name, str) and
        len(name) <= MAX_POOL_NAME_LEN and
        bool(re.fullmatch(r"[A-Za-z0-9_-]+", name))
    )


def _is_safe_string(value, max_len):
    return (
        isinstance(value, str) and
        len(value) <= max_len and
        bool(SAFE_STR_PATTERN.fullmatch(value))
    )


def _validate_configuration(cfg):
    if not _is_valid_ip(getattr(cfg, "san_ip", None)):
        raise ValueError("Invalid SAN IP address")
    if not _is_allowed_cli_path(getattr(cfg, "naviseccli_path", "")):
        raise ValueError("naviseccli_path is not an allowed executable")
    if not _is_valid_pool_name(getattr(cfg, "storage_vnx_pool_name", "")):
        raise ValueError("Invalid storage pool name")
    # Validate additional configurable string fields
    for field, max_len in (
        ("username", MAX_USERNAME_LEN),
        ("password", MAX_PASSWORD_LEN),
        ("extra_cli_args", MAX_EXTRA_ARGS_LEN),
    ):
        if hasattr(cfg, field):
            value = getattr(cfg, field)
            if isinstance(value, str) and not _is_safe_string(value, max_len):
