    """Perform a TOCTOUâsafe validation of the executable just before execution."""
    if not isinstance(exec_path, str) or not os.path.isabs(exec_path):
        raise ValueError("Executable path must be an absolute string")
    real_path = os.path.realpath(exec_path)
    allowed = {
        "/opt/emc/cli/naviseccli",
        "/usr/local/bin/naviseccli",
    }
    if real_path not in allowed:
        raise ValueError("Executable not whitelisted")
    try:
        fd = os.open(real_path, os.O_RDONLY | os.O_NOFOLLOW)
    except OSError as e:
        raise ValueError(f"Unable to open executable securely: {e}") from e
    try:
        st = os.fstat(fd)
        if not stat.S_ISREG(st.st_mode):
            raise ValueError("Executable is not a regular file")
        if st.st_uid != 0:
            raise ValueError("Executable not owned by root")
        if not (st.st_mode & (stat.S_IXUSR | stat.S_IXGRP | stat.S_IXOTH)):
            raise ValueError("Executable is not executable")
        if st.st_mode & (stat.S_IWGRP | stat.S_IWOTH):
            raise ValueError("Executable must not be writable by group or others")
    finally:
        os.close(fd)


def _safe_execute(self, cmd, *args, **kwargs):
    """Execute external commands safely without invoking a shell."""
    if isinstance(cmd, str):
        raise ValueError("Command must be provided as a list, not a string")
    if not isinstance(cmd, (list, tuple)):
        raise ValueError("Command must be a list or tuple of arguments")
    if not cmd:
        raise ValueError("Command list cannot be empty")
    # Validate that the executable itself passes all checks at execution time
