    # Resolve both paths (follow symlinks) without requiring the target to exist
    resolved_target = target_path.resolve(strict=False)
    resolved_base = base_dir.resolve(strict=True)   # base directory must exist

    # Verify that the resolved target is inside the resolved base directory
    if os.name == "nt":
        # Windows â caseâinsensitive comparison
        target_str = resolved_target.as_posix().casefold()
        base_str = resolved_base.as_posix().casefold()
        if not (target_str == base_str or target_str.startswith(base_str + "/")):
            raise ValueError("Resulting path is outside the allowed attachments directory")
    else:
        # POSIX â use pathlib's relative check
        try:
            resolved_target.relative_to(resolved_base)
        except ValueError as exc:
            raise ValueError("Resulting path is outside the allowed attachments directory") from exc

    return str(resolved_target)

