def _validate_uuid(value: str) -> str:
    if not isinstance(value, str):
        raise InvalidInputError("UUID must be a string")
    try:
        return str(uuid.UUID(value))
    except (ValueError, AttributeError) as exc:
        raise InvalidInputError("Invalid UUID format") from exc

def _sanitize_string(value: str, max_length: int = 150) -> str:
    if not isinstance(value, str):
        raise InvalidInputError("Expected string input")
    sanitized = value.strip()
    if not (0 < len(sanitized) <= max_length):
        raise InvalidInputError("String input out of allowed length")
    if not _ALLOWED_CHARS_PATTERN.fullmatch(sanitized):
        raise InvalidInputError("String contains disallowed characters")
    return sanitized

