# Hardâcoded safe PATH directories.
_WHITELIST_PATHS = ("/usr/bin", "/bin", "/usr/sbin", "/sbin")

# Disallowed curl flags that can read/write files, affect networking, or modify TLS.
_DISALLOWED_FLAGS = {
    "-o", "--output", "--output-dir", "-O", "--config",
    "-d", "--data", "--data-binary", "--data-raw", "--data-urlencode",
    "--form", "--form-string", "--upload-file",
    "--proxy", "--proxy-user", "--proxy-pass", "--proxy-header",
    "--interface", "--resolve", "--tls-max", "--ciphers",
}
# Flags that consume the next token as a value.
_ARG_CONSUMING_FLAGS = {
    "-o", "--output", "--output-dir",
    "-d", "--data", "--data-binary", "--data-raw", "--data-urlencode",
    "--form", "--form-string", "--upload-file",
    "--proxy", "--proxy-user", "--proxy-pass", "--proxy-header",
    "--interface", "--resolve", "--tls-max", "--ciphers",
}

# Maximum allowed download size in bytes (10â¯MiB).
_MAX_DOWNLOAD_SIZE = 10 * 1024 * 1024

# Maximum command string length (4â¯KB).
_MAX_COMMAND_LENGTH = 4 * 1024

def _resolve_curl_executable() -> str:
    """Return an absolute path to the curl binary from a whitelist of directories."""
    for directory in _WHITELIST_PATHS:
        candidate = os.path.join(directory, "curl")
        if not os.path.isfile(candidate):
            continue
        if not os.access(candidate, os.X_OK):
            continue
        if os.path.islink(candidate):
            continue
        try:
            st = os.stat(candidate)
        except OSError:
            continue
        # Require the binary to be owned by root (uid 0) or by the current user.
        if st.st_uid not in (0, os.getuid()):
            continue
        return candidate
    raise RuntimeError("curl executable not found in whitelist directories")

def _is_disallowed_flag(token: str, next_token: str | None) -> bool:
    """Detect whether a token (or its combination with the following token) is disallowed."""
    if token in _DISALLOWED_FLAGS:
        return True
    if token.startswith("--"):
        # Long options with =value form.
        for flag in _DISALLOWED_FLAGS:
            if flag.startswith("--") and token.startswith(flag + "="):
                return True
    if token.startswith("-") and not token.startswith("--"):
        # Expand grouped short options.
        for ch in token[1:]:
            short_opt = f"-{ch}"
            if short_opt in _DISALLOWED_FLAGS:
                return True
            if short_opt in {"-o"} and next_token and not next_token.startswith("-"):
                return True
    return False

def _validate_url_scheme(url: str) -> None:
    """Allow only http and https schemes."""
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme.lower() not in {"http", "https"}:
        raise ValueError(f"Disallowed URL scheme in '{url}'")

def _execute_command(command: str) -> bool:
    if not isinstance(command, str):
        raise TypeError("command must be a string")
    if len(command) > _MAX_COMMAND_LENGTH:
        raise ValueError("command exceeds maximum allowed length")

    try:
