    if os.path.basename(args[0]) != "curl":
        raise ValueError("Only 'curl' commands are permitted")
    args[0] = curl_path

    # Simple redirection guard.
    redir_prefixes = {">", ">>", "2>", "&>", "|", ";", "&&", "||", "`"}
    for tok in args:
        for prefix in redir_prefixes:
            if tok == prefix or tok.startswith(prefix):
                raise ValueError(f"Shell redirection operator '{tok}' is not allowed")

    # Scan arguments for disallowed flags and collect URLs.
    i = 1
