    try:
        with tempfile.NamedTemporaryFile(dir=work_dir, delete=False) as tmp_out:
            temp_path = tmp_out.name

        try:
            with open(temp_path, "wb") as stdout_f:
                result = subprocess.run(
                    args,
                    stdout=stdout_f,
                    stderr=subprocess.PIPE,
                    cwd=work_dir,
                    env=env,
                    timeout=30,
                    check=False,
                    close_fds=True,
                )
        finally:
            try:
                os.remove(temp_path)
            except OSError:
                pass

        if result.returncode != 0:
            logging.error("Command exited with non-zero status %s", result.returncode)
            raise RuntimeError("Command execution failed")
    except subprocess.TimeoutExpired as exc:
        raise RuntimeError(f"Command timed out after {exc.timeout} seconds") from exc
    except OSError as exc:
        raise RuntimeError(f"Failed to launch command: {exc}") from exc
    finally:
        shutil.rmtree(work_dir, ignore_errors=True)

