    try:
        # Python 3.9+
        if not version_path.is_relative_to(project_root):
            raise RuntimeError("Invalid version file location")
    except AttributeError:
        # Fallback for older Python versions
        if project_root not in version_path.parents:
            raise RuntimeError("Invalid version file location")

    if not version_path.is_file():
        raise FileNotFoundError(f"Version file not found: {version_path}")

    try:
        source = version_path.read_text(encoding="utf-8")
    except Exception as exc:
        raise RuntimeError("Failed to read version file") from exc

    try:
        tree = ast.parse(source, filename=str(version_path))
    except SyntaxError as exc:
        raise RuntimeError("Malformed version file") from exc

    version: dict[str, str] = {}
    for node in ast.iter_child_nodes(tree):
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name) and target.id == "__version__":
                    if isinstance(node.value, ast.Str):
                        version_str = node.value.s
                    elif isinstance(node.value, ast.Constant) and isinstance(node.value.value, str):
                        version_str = node.value.value
                    else:
