                    if not re.fullmatch(r"\d+\.\d+\.\d+(?:[A-Za-z0-9.-]*)?", version_str):
                        raise RuntimeError(f"Invalid version format: {version_str}")

                    version["__version__"] = version_str
                    break
            if "__version__" in version:
                break

    if "__version__" not in version:
