    "sha512",
    "blake2b",
}


def _validate_path(file_path: Path) -> Path:
    """
    Resolve the path securely and ensure it is within the allowed directory.
    """
    try:
        resolved = file_path.resolve(strict=True)
    except FileNotFoundError as e:
        raise FileNotFoundError(f"File not found: {file_path}") from e
    except PermissionError as e:
        raise PermissionError(f"Permission denied while resolving: {file_path}") from e
    except OSError as e:
        raise OSError(f"Unable to resolve path: {file_path}") from e

    # Ensure the resolved path is inside the allowed root
    try:
        if not resolved.is_relative_to(ALLOWED_ROOT):
            raise ValueError(f"Access to path outside allowed directory is prohibited: {resolved}")
    except AttributeError:  # Python < 3.9 fallback
        if not str(resolved).startswith(str(ALLOWED_ROOT) + os.sep):
            raise ValueError(f"Access to path outside allowed directory is prohibited: {resolved}")

    return resolved


def _open_file_no_follow(path: Path):
    """
    Open a file descriptor without following symlinks and verify it is a regular file.
    Returns a file object opened in binary mode.
    """
    flags = os.O_RDONLY | getattr(os, "O_NOFOLLOW", 0)
    try:
        fd = os.open(path, flags)
    except FileNotFoundError as e:
        raise FileNotFoundError(f"File not found: {path}") from e
    except PermissionError as e:
        raise PermissionError(f"Permission denied: {path}") from e
    except OSError as e:
        raise OSError(f"Failed to open file: {path}") from e

    try:
        stat_result = os.fstat(fd)
        if not stat_result.st_mode & 0o170000 == 0o100000:  # S_IFREG
            raise ValueError(f"Path is not a regular file: {path}")
        return os.fdopen(fd, "rb")
    except Exception:
        os.close(fd)
        raise


def gethash(filename: str, algorithm: str) -> str:
    """
    Calculate the hexadecimal hash digest of a file using a whitelisted algorithm.

    Args:
        filename: Path to the target file.
        algorithm: Name of the hash algorithm (e.g., "sha256").

    Returns:
        Hexadecimal digest string.

    Raises:
        ValueError: Invalid inputs or unsupported algorithm.
        FileNotFoundError: File does not exist.
        PermissionError: Insufficient permissions.
        OSError: Other I/O errors.
    """
    # Validate filename type
    if not isinstance(filename, (str, bytes, os.PathLike)):
        raise ValueError("filename must be a string, bytes, or pathâlike object")

    # Validate hash algorithm
    if not isinstance(algorithm, str):
        raise ValueError("algorithm must be a string")
    algo_lower = algorithm.lower()
    if algo_lower not in SUPPORTED_HASHES:
        raise ValueError(f"Unsupported or weak hash algorithm: {algorithm}")

    # Resolve and validate path
    path = Path(filename)
    safe_path = _validate_path(path)

    # Open file securely and verify regular file
    try:
        with _open_file_no_follow(safe_path) as f:
            # Instantiate hash object
            try:
