            except Exception as e:
                raise ValueError(f"Failed to instantiate hash algorithm '{algorithm}'") from e

            # Read and update hash
            while True:
                chunk = f.read(8192)
                if not chunk:
                    break
                hasher.update(chunk)

            # Produce digest
            try:
                return hasher.hexdigest()
            except Exception as e:
                raise ValueError("Failed to generate hash digest") from e
    except Exception as e:
        # Propagate known exception types; wrap unexpected ones
        if isinstance(e, (FileNotFoundError, PermissionError, ValueError)):
            raise
        raise OSError("Error processing the file") from e

