import logging
import ipaddress
from typing import Any, Mapping, Callable

logger = logging.getLogger(__name__)

_CONTAINER_NAME_RE = re.compile(r'^[a-zA-Z0-9._-]+$')
_HOSTNAME_LABEL_RE = re.compile(r'^[a-zA-Z0-9-]{1,63}$')
_ILLEGAL_CHARS = ('
', '', '�')


def _validate_str(value: Any, name: str) -> str:
    if not isinstance(value, str):
        raise TypeError(f"{name} must be a string")
    if any(c in value for c in _ILLEGAL_CHARS):
        raise ValueError(f"{name} contains illegal characters")
    return value.strip()


def _validate_ip(ip: Any) -> str:
    if not isinstance(ip, str):
        raise TypeError("IP address must be a string")
    ip = ip.strip()
    try:
        ipaddress.ip_address(ip)
    except ValueError as exc:
        raise ValueError("Invalid IP address") from exc
    return ip


def _validate_container_name(name: Any) -> str:
    name = _validate_str(name, "container name")
    if not _CONTAINER_NAME_RE.fullmatch(name):
        raise ValueError("Invalid container name")
    if name.startswith('-'):
        raise ValueError("Container name must not start with '-'")
    return name


def _validate_hostname(hostname: Any) -> str:
    hostname = _validate_str(hostname, "hostname")
    labels = hostname.split('.')
    if not labels:
        raise ValueError("Hostname cannot be empty")
    for label in labels:
        if not _HOSTNAME_LABEL_RE.fullmatch(label):
            raise ValueError(f"Invalid hostname label: {label}")
    return hostname


def _extract_and_validate(mapping: Mapping[str, Any], key: str, validator: Callable[[Any], Any]) -> Any:
    if key not in mapping:
        raise KeyError(f"Missing required key: {key}")
    return validator(mapping[key])


def update_dns(node_this: Mapping[str, Any], node_other: Mapping[str, Any]) -> bool:
    """
    Append an entry for ``node_other`` to the /etc/hosts file of ``node_this`` container.

    Returns True on success, False otherwise.
    """
    try:
        this_name = _validate_container_name(
            _extract_and_validate(node_this, 'name', lambda v: v)
        )
        other_ip = _validate_ip(
            _extract_and_validate(node_other, 'ip_addr', lambda v: v)
        )
        other_name = _validate_hostname(
            _extract_and_validate(node_other, 'name', lambda v: v)
        )

        hosts_entry = f"{other_ip} {other_name}"
        quoted_entry = shlex.quote(hosts_entry)

        cmd = [
            "docker", "exec",
            "-u", "root",
            "-i", this_name,
            "bash", "-c",
            f"echo {quoted_entry} >> /etc/hosts"
        ]

        subprocess.run(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            check=True
        )
        return True
    except (KeyError, TypeError, ValueError, subprocess.CalledProcessError) as exc:
        logger.error("Failed to update DNS: %s", exc)
        return False
    except Exception as exc:  # pragma: no cover
        logger.exception("Unexpected error in update_dns")
        return False

