from typing import Optional, Callable

def _is_safe_path_component(comp: str) -> bool:
    if ".." in comp or comp.startswith("."):
        return False
    return bool(re.fullmatch(r"[A-Za-z0-9._-]+", comp))

def _is_safe_ffmpeg_name(name: str) -> bool:
    if name.startswith(("@", "-", "pipe:")):
        return False
    return _is_safe_path_component(name)

def _validate_int(value, name: str, min_val: int, max_val: int) -> int:
    try:
        ivalue = int(value)
    except (TypeError, ValueError):
        raise ValueError(f"{name} must be an integer")
    if not (min_val <= ivalue <= max_val):
        raise ValueError(f"{name} must be between {min_val} and {max_val}")
    return ivalue

def _resolve_ffmpeg_path(user_path: Optional[str] = None) -> str:
    allowed_dirs = {"/usr/bin", "/usr/local/bin", "/bin", "/sbin"}
    if user_path:
        ffmpeg_path = shutil.which(user_path)
        if not ffmpeg_path:
            raise FileNotFoundError(f"Specified ffmpeg executable not found: {user_path}")
    else:
        ffmpeg_path = shutil.which("ffmpeg")
        if not ffmpeg_path:
            raise FileNotFoundError("ffmpeg executable not found in PATH")
    real_path = os.path.realpath(ffmpeg_path)
    if not any(os.path.commonpath([real_path, d]) == d for d in allowed_dirs):
        raise ValueError(f"ffmpeg executable '{real_path}' is not located in an allowed directory")
    return real_path

def _sanitize_log(msg: str, max_len: int = 1024) -> str:
    safe = "".join(ch if ch.isprintable() else "?" for ch in msg)
    return safe[:max_len]

def _preexec_sandbox():
    if os.getuid() == 0:
        try:
            nobody = pwd.getpwnam("nobody")
            os.setgid(nobody.pw_gid)
            os.setuid(nobody.pw_uid)
