    new_width = _validate_int(newWidth, "newWidth", 1, 3840)
    new_height = _validate_int(newHeight, "newHeight", 1, 3840)
    bitrate = _validate_int(bitrate, "bitrate", 1, 10000)

    ffmpeg_path = _resolve_ffmpeg_path(ffmpeg)

    input_path = f"{saveText}.{imageFormat}"
