    r'^[0-9]+(?:\.[0-9]+)*(?:[a-zA-Z0-9]+)?$'
)


def _extract_version(source: str, filename: str) -> str:
    """Extract the version string from Python source code.

    Tries a simple regex first; if that fails, falls back to AST parsing.
    Raises RuntimeError if the version cannot be determined or is malformed.
