class Helpers:
    """
    Utility helper methods.
    """

    _website_pattern = re.compile(r'^[a-zA-Z0-9.\-]+$')
    _max_website_len = 255
    _max_timestamp_len = 64
    _min_secret_len = 16  # bytes

    @staticmethod
    def _sanitize_website(website: str) -> str:
        if not isinstance(website, str):
            raise ValueError("Website must be a string")
        website = website.strip()
        if not website:
            raise ValueError("Website cannot be empty")
        if len(website) > Helpers._max_website_len:
            raise ValueError("Website exceeds maximum length")
        if not Helpers._website_pattern.fullmatch(website):
            raise ValueError("Website contains prohibited characters")
        return website.lower()

    @staticmethod
    def _sanitize_timestamp(ts: Union[str, datetime.datetime]) -> str:
        if isinstance(ts, datetime.datetime):
            # Ensure UTC timezone
            if ts.tzinfo is None:
                ts = ts.replace(tzinfo=datetime.timezone.utc)
            else:
                ts = ts.astimezone(datetime.timezone.utc)
            return ts.isoformat()
        if not isinstance(ts, str):
            raise ValueError("Timestamp must be a string or datetime")
        ts = ts.strip()
        if not ts:
            raise ValueError("Timestamp cannot be empty")
        if len(ts) > Helpers._max_timestamp_len:
            raise ValueError("Timestamp exceeds maximum length")
        try:
            parsed = datetime.datetime.fromisoformat(ts)
        except Exception as exc:
            raise ValueError("Timestamp is not a valid ISOâ8601 string") from exc
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=datetime.timezone.utc)
        else:
            parsed = parsed.astimezone(datetime.timezone.utc)
        return parsed.isoformat()

    @staticmethod
    def _derive_secret() -> bytes:
        """
        Retrieve a secret for HMAC generation.
        Preference is given to the APP_ID_SECRET environment variable.
        The secret must be at least _min_secret_len bytes when UTFâ8 encoded.
        If not provided, a oneâtime secret is generated for the process.
        """
        env_secret = os.getenv('APP_ID_SECRET')
        if env_secret is not None:
            secret_bytes = env_secret.encode('utf-8')
            if len(secret_bytes) < Helpers._min_secret_len:
                raise ValueError("APP_ID_SECRET is too short")
            return secret_bytes
        # Oneâtime secret for the lifetime of the process
        return secrets.token_bytes(32)

    @staticmethod
    def make_id(website: str, timestamp: Union[str, datetime.datetime]) -> str:
        """
        Create a deterministic, cryptographicallyâsafe identifier for a given
        website and timestamp.

        Parameters
        ----------
        website : str
            The website domain or identifier.
        timestamp : str or datetime.datetime
            ISOâ8601 timestamp or datetime object.

        Returns
        -------
        str
            A 64âcharacter hexadecimal ID.
        """
        try:
            clean_site = Helpers._sanitize_website(website)
            clean_ts = Helpers._sanitize_timestamp(timestamp)
            secret = Helpers._derive_secret()
            payload = f'{clean_site}|{clean_ts}'.encode('utf-8')
            mac = hashlib.pbkdf2_hmac('sha256', payload, secret, 100_000)
            return mac.hex()
