        logging.warning("RSS object of type %s has no __dict__; skipping sanitization.", type(rss_obj).__name__)
        return

    for attr_name, attr_val in list(vars(rss_obj).items()):
        if attr_name.startswith("_"):
            continue
        try:
            sanitized = _sanitize_value(attr_val)
            rss_obj.__dict__[attr_name] = sanitized
        except Exception as exc:
            logging.warning(
                "Unable to sanitize attribute %s of %s: %s", attr_name, type(rss_obj).__name__, exc
            )


class SizeLimitedBuffer(io.BytesIO):
    """Buffer that aborts if the written content exceeds MAX_RSS_SIZE."""

    def write(self, b):
        if not isinstance(b, (bytes, bytearray)):
            raise TypeError("Only bytes may be written to SizeLimitedBuffer")
        if self.tell() + len(b) > MAX_RSS_SIZE:
            raise ValueError("Generated RSS exceeds maximum allowed size")
        return super().write(b)


def generate_rss(rss, output):
    """Generate an RSS feed safely, enforcing size limits and proper sanitisation."""
    _sanitize_rss(rss)

    # Determine whether we need to wrap the output
    if isinstance(output, SizeLimitedBuffer):
        target = output
        owns_target = False
    else:
        target = SizeLimitedBuffer()
        owns_target = True

    try:
        rss.write_xml(target, encoding="utf-8")
        xml_content = target.getvalue()
        if owns_target:
            # Write the safely sized content to the caller-provided stream
            output.write(xml_content)
    except (IOError, OSError) as e:
        logging.error("RSS generation error: %s", e)
        raise RuntimeError("Failed to generate RSS feed") from e
    finally:
        # Close only streams we opened ourselves
        if owns_target:
            try:
                target.close()
            except Exception as exc:
                logging.warning("Error closing internal buffer: %s", exc)

    if len(xml_content) > MAX_RSS_SIZE:
        raise ValueError("Generated RSS exceeds maximum allowed size")

    return xml_content.decode("utf-8") if isinstance(xml_content, (bytes, bytearray)) else xml_content

